window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q16"]=window.__LIBQ["tien-nghich"]["q16"]||{};window.__LIBQ["tien-nghich"]["q16"]["artifacts"]={"updatedAt":"2026-07-17","count":58,"artifacts":[{"id":"cuu-huyen-huyet-mach","name":"Cửu huyền huyết mạch","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Đạo nhân bảy màu"],"trangThai":"đã tập hợp toàn bộ","blurb":"Chín huyết cầu lớn mà Đạo nhân bảy màu đã tập hợp đầy đủ, dự định dùng huyễn hóa luân hồi để tìm hồn thứ ba.","detail":"Gồm chín huyết cầu lớn, được Đạo nhân bảy màu (phân thân bảy màu của Vương Lâm) thu thập đầy đủ trong Côn Hư. Sẽ dùng lực lượng này huyễn hóa luân hồi để truy tìm hồn thứ ba đã trốn vào luân hồi năm đó.","nguon":["@c1633"]},{"id":"ngoc-gian-toa-do-ngu-hanh","name":"Ngọc giản tọa độ Ngũ Hành tinh","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Ngọc giản chứa tọa độ Ngũ Hành tinh, do Nạp Đa đưa cho Vương Lâm hơn ngàn năm trước khi mời hắn tới.","detail":"Vật mà Nạp Đa đưa cho Vương Lâm hơn ngàn năm trước, chứa tọa độ Ngũ Hành tinh. Vương Lâm dùng ngọc giản này để tìm phương hướng đến Ngũ Hành tinh — tu chân tinh thần bí nhất Côn Hư mà ngay cả Tu Chân Liên Minh cũng không biết vị trí.","congNang":["Chứa tọa độ Ngũ Hành tinh, dùng để tìm phương hướng đến tinh cầu"],"nguonGoc":"Do Nạp Đa đưa cho Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1634","denChuong":"","cachCoDuoc":"Nạp Đa đưa hơn ngàn năm trước","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1634","loai":"dùng","importance":"normal","giaiDoan":"Vương Lâm dùng ngọc giản tìm Ngũ Hành tinh","text":"Vương Lâm cưỡi U Minh thú, cầm ngọc giản tìm phương hướng của Ngũ Hành tinh theo tọa độ bên trong.","anchor":"trong tay cầm ngọc giản, cẩn thận tìm phương hướng của Ngũ Hành tinh"}]},"nguon":["@c1634"]},{"id":"tran-linh-dai-dia-tho-tran","name":"Trận linh Đại địa thổ trận","cn":"","category":"khac","categoryLabel":"Trận linh","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Bị Vương Lâm thu giữ","blurb":"Dúm bùn đất tỏa linh khí dày đặc, là trận linh của Đại địa thổ trận thuộc Ngũ hành đại trận.","detail":"Trận linh của trận thứ nhất Đại địa thổ trận. Khi Vương Lâm phá trận, vô số bùn đất ngưng tụ thành một dúm tỏa linh khí dày đặc. Bị Vương Lâm thu vào lòng bàn tay phải rồi cất giữ. Việc thu trận linh khiến bốn trưởng lão và Nạp Đa đều chấn động.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1635","denChuong":"","cachCoDuoc":"Thu sau khi phá Đại địa thổ trận","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1635","loai":"đổi chủ","importance":"normal","giaiDoan":"Bị Vương Lâm thu","text":"Vương Lâm phá Đại địa thổ trận, bùn đất ngưng tụ thành trận linh tỏa linh khí dày đặc, bị thu vào lòng bàn tay phải.","anchor":"Chúng hóa thành một dúm đất! Một dúm bùn đất này tỏa ra linh khí dày đặc, chính là trận linh của Ngũ hành đại trận"}]},"nguon":["@c1635"]},{"id":"truong-thuong-song-nuoc","name":"Trường thương sóng nước","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thủy Tướng"],"trangThai":"dang-dung","blurb":"Trường thương do Thủy Tướng triệu ra từ vùng sóng nước trong hư không, dùng kết hợp cùng tiên tổ chiến giáp để chuẩn bị vào Ngũ Hành thủy trận đối đầu Vương Lâm.","detail":"Thủy Tướng chụp vào hư không triệu ra vùng sóng nước hóa thành một thanh trường thương rất lớn, là vũ khí thủy hệ phối hợp cùng tiên tổ chiến giáp.","congNang":["Vũ khí chiến đấu thủy hệ, triệu từ sóng nước trong hư không"],"tabs":{"tienTrinh":[{"chuong":"@c1636","loai":"xuat-hien","importance":"normal","giaiDoan":"Xuất hiện lần đầu","text":"Thủy Tướng triệu trường thương sóng nước từ hư không sau khi mặc tiên tổ chiến giáp, chuẩn bị vào Ngũ Hành thủy trận đối đầu Vương Lâm.","anchor":"Lập tức trong tay hắn xuất hiện một vùng sóng nước, hóa thành một thanh trường thương rất lớn"}]},"chuSoHuu":[{"ten":"Thủy Tướng","tuChuong":"@c1636","denChuong":"","cachCoDuoc":"Triệu từ sóng nước","trangThai":"dang-dung"}],"nguon":["@c1636"]},{"id":"ao-giap-thuy-tuong","name":"Áo giáp Thủy Tướng","cn":"水将战甲","aliases":["Tiên tổ chiến giáp","Áo giáp lam Thủy Tướng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (ở tiên tộc rất có danh tiếng)","soHuu":["Thủy Tướng"],"trangThai":"Đang được Thủy Tướng mặc, bí mật bị Vương Lâm nhìn thấu","blurb":"Áo giáp lam đặc biệt của Thủy Tướng Quy Nhất tông, ở tiên tộc rất có danh tiếng. Cho phép người mặc đánh ra lực lượng bước thứ ba dù tu vi chưa tới, đồng thời phóng sinh cơ khôi phục thương thế, nhưng tác dụng phụ nguy hiểm là áo giáp điều khiển ngược người mặc chứ không phải ngược lại.","detail":"Áo giáp đặc biệt mà Thủy Tướng Quy Nhất tông khoác trên người trong trận chiến với Vương Lâm. Khi Thủy Tướng bị Vương Lâm đánh tan ngũ tạng, áo giáp xuất hiện khe nứt li ti nhưng không tan, từ trong khe phóng ra sinh cơ khôi phục thương thế cho người mặc. Áo giáp còn cho phép đánh ra lực lượng bước thứ ba dù tu vi thực tế chưa đạt tới mức đó. Tuy nhiên, bí mật nguy hiểm của nó là áo giáp điều khiển người mặc chứ không phải người mặc điều khiển áo giáp — điều mà Vương Lâm dùng cấm chế bổn nguyên tự hình thành quy tắc nhìn thấu được. Huyền La Đại Thiên Tôn nhận xét áo giáp này ở tiên tộc cũng rất có danh tiếng.","hinhDang":"Áo giáp lam sắc","congNang":["Cho phép người mặc đánh ra lực lượng bước thứ ba dù tu vi chưa tới @c1637","Phóng sinh cơ khôi phục thương thế khi người mặc bị thương nặng","Điều khiển ngược người mặc — áo giáp kiểm soát chủ nhân chứ không phải ngược lại @c1637"],"dacDiem":"Tác dụng phụ nguy hiểm: áo giáp điều khiển người mặc chứ không phải ngược lại, bản chất là vật phẩm chi phối chủ nhân","uyLuc":"Ở tiên tộc rất có danh tiếng, có thể nâng sức mạnh người mặc lên tầm bước thứ ba","chuSoHuu":[{"ten":"Thủy Tướng","tuChuong":"@c1637","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"đang mặc"}],"tabs":{"tienTrinh":[{"chuong":"@c1637","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Bí mật bị nhìn thấu","text":"Vương Lâm dùng cấm chế bổn nguyên nhìn thấu bí mật: áo giáp cho sức mạnh bước ba nhưng điều khiển ngược người mặc. Khi Thủy Tướng bị đánh, áo giáp nứt nhỏ nhưng không tan, phóng sinh cơ hồi phục thương thế.","anchor":"tu vi của ngươi không tới bước thứ ba nhưng sau khi mặc áo giáp này vào lại có thể đánh ra lực lượng của bước thứ ba"}]},"capNhatToi":"@c1637","nguon":["@c1637"]},{"id":"ao-giap-kim-quang-nap-da","name":"Áo giáp kim quang của Nạp Đa","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nạp Đa"],"trangThai":"Đang sử dụng","blurb":"Bộ áo giáp kim quang chói mắt do Nạp Đa bắt quyết hóa thành, mặc vào tu vi tăng mạnh.","detail":"Nạp Đa bắt quyết, kim quang lóe lên hóa thành bộ áo giáp tỏa kim quang chói mắt trên thân, tu vi tăng mạnh đáng kể sau khi mặc vào. Thuộc hệ kim.","congNang":["Gia tăng tu vi cho người mặc"],"chuSoHuu":[{"ten":"Nạp Đa","tuChuong":"@c1639","denChuong":"","cachCoDuoc":"Tự có","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1639","loai":"xuất hiện","importance":"normal","giaiDoan":"Nạp Đa mặc giáp nhập trận","text":"Nạp Đa bắt quyết hóa áo giáp kim quang chói mắt trên thân, tu vi tăng mạnh, dẫn đầu mấy trăm tu sĩ phóng thần thức nhập Ngũ Hành thủy trận đè ép Vương Lâm.","anchor":"Lập tức những luồng kim quang lóe lên, hóa thành một bộ áo giáp tỏa kim quang chói mắt trên thân thể hắn"}]},"nguon":["@c1639"]},{"id":"giot-nuoc-thuy-bon-nguyen","name":"Giọt nước thủy bổn nguyên","cn":"","category":"khac","categoryLabel":"Vật phẩm bổn nguyên","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đã dùng hết","blurb":"Giọt nước ẩn chứa một tia thủy bổn nguyên mà Thiên Vận Tử cho Vương Lâm, trở thành chìa khóa hoàn tất minh ngộ thủy bổn nguyên trong lúc đối mặt thủy cầu Càn Khôn Nhất Tích.","detail":"Giọt nước này do Thiên Vận Tử trao cho Vương Lâm từ trước, bên trong ẩn chứa một tia thủy bổn nguyên. Trong lúc bị thủy cầu của chiêu Càn Khôn Nhất Tích đè ép, Vương Lâm lấy giọt nước ra; nó tỏa sáng xoay tròn trên lòng bàn tay, đóng vai trò xúc tác giúp Vương Lâm hoàn tất minh ngộ ba triệu tám ngàn vạn lần biến hóa của thủy bổn nguyên. Sau khi quá trình minh ngộ hoàn thành, toàn bộ thủy cầu ngưng tụ thành giọt nước thủy tinh trên lòng bàn tay rồi tiêu tán.","congNang":["Chứa một tia thủy bổn nguyên @c1639","Xúc tác hoàn tất minh ngộ ba triệu tám ngàn vạn lần biến hóa thủy bổn nguyên @c1639"],"chuSoHuu":[{"ten":"Thiên Vận Tử","tuChuong":"","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"da-cho"},{"ten":"Vương Lâm","tuChuong":"@c1639","denChuong":"@c1639","cachCoDuoc":"Thiên Vận Tử cho","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1639","loai":"dùng","importance":"major","giaiDoan":"Xúc tác minh ngộ thủy bổn nguyên","text":"Vương Lâm lấy giọt nước ra trong lúc bị thủy cầu đè ép, giọt nước tỏa sáng xoay tròn trên tay, trở thành chìa khóa hoàn tất minh ngộ ba triệu tám ngàn vạn lần biến hóa thủy bổn nguyên. Toàn bộ thủy cầu ngưng tụ vào giọt nước thủy tinh trên lòng bàn tay rồi tiêu tán.","anchor":"trong tay hắn liền xuất hiện một giọt nước ẩn chứa một tia thủy bổn nguyên mà Thiên Vận Tử cho hắn lúc trước"}]},"nguon":["@c1639"],"dacDiem":"Khi được lấy ra, giọt nước tỏa sáng và xoay tròn trên lòng bàn tay; sau khi hoàn thành tác dụng, thủy cầu xung quanh ngưng tụ thành giọt nước thủy tinh rồi tiêu tán @c1639"},{"id":"mam-mong-thuy-bon-nguyen","name":"Mầm mống thủy bổn nguyên","cn":"","category":"khac","categoryLabel":"Bổn nguyên","phamCap":"Thực bổn nguyên","soHuu":["Vương Lâm"],"trangThai":"mầm mống, chưa đại thành","blurb":"Mầm mống thủy bổn nguyên là bổn nguyên thứ tám của Vương Lâm, thuộc loại thực bổn nguyên, hình thành nhờ hấp thu Càn Khôn Nhất Tích. Đây là nền tảng thủy bổn nguyên trong ngũ hành, cần dung hợp nhiều lần mới đại thành, khác với hư bổn nguyên dựa vào cảm ngộ.","detail":"Mầm mống thủy bổn nguyên xuất hiện trong thân thể Vương Lâm sau khi hấp thu Càn Khôn Nhất Tích (@c1640). Đây là bổn nguyên thứ tám mà Vương Lâm có được, thuộc hệ thực bổn nguyên — cùng loại với hỏa bổn nguyên và lôi bổn nguyên — nghĩa là cần trải qua nhiều lần dung hợp mới có thể đại thành, khác biệt căn bản so với các hư bổn nguyên như nhân quả, sinh tử, chân giả vốn dựa vào cảm ngộ để thành tựu. Mầm mống thủy bổn nguyên đóng vai trò là nền tảng thủy bổn nguyên trong hệ thống ngũ hành bổn nguyên.","congNang":["Chứa bổn nguyên thủy, là nền tảng thủy bổn nguyên trong ngũ hành (@c1640)"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1640","denChuong":"","cachCoDuoc":"Hấp thu Càn Khôn Nhất Tích","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1640","loai":"xuất hiện","importance":"major","giaiDoan":"Hình thành mầm mống","text":"Vương Lâm có được mầm mống thủy bổn nguyên — bổn nguyên thứ tám — nhờ hấp thu Càn Khôn Nhất Tích. Là thực bổn nguyên cần dung hợp nhiều lần mới đại thành.","anchor":"Bổn nguyên thứ tám này chính là thủy bổn nguyên"}]},"nguon":["@c1640"]},{"id":"tinh-the-xanh-biec-moc-linh","name":"Tinh thể xanh biếc (mộc linh)","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Tinh thể ngưng tụ từ sinh cơ của mộc linh khi quy phục Vương Lâm trong Ngũ Hành mộc trận, tràn ngập sinh cơ màu xanh biếc.","detail":"Khi mộc linh trong Ngũ Hành mộc trận quy phục Vương Lâm, nó ngưng tụ toàn bộ sinh cơ hóa thành một tinh thể xanh biếc tràn ngập sinh cơ bay thẳng tới tay hắn. Tinh thể này tương tự tinh thể thu được từ thủy trận trước đó, thuộc chuỗi thu thập tinh hoa ngũ hành.","congNang":["Chứa đựng sinh cơ ngưng tụ của mộc linh Ngũ Hành đại trận"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1641","denChuong":"","cachCoDuoc":"Mộc linh quy phục trao tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1641","loai":"xuat-hien","importance":"normal","giaiDoan":"Mộc linh quy phục, ngưng tụ tinh thể","text":"Mộc linh trong Ngũ Hành mộc trận quy phục Vương Lâm, ngưng tụ sinh cơ hóa thành tinh thể xanh biếc tràn ngập sinh cơ bay tới tay hắn.","anchor":"một vùng sáng màu xanh biếc tràn ngập sinh cơ ngưng tụ ra, hóa thành một tinh thể xanh biếc bay thẳng về hướng Vương Lâm"}]},"nguon":["@c1641"]},{"id":"roi-xanh-biec","name":"Roi xanh biếc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lão già tóc bạc tầng ba"],"trangThai":"hong","blurb":"Roi mộc lực Ngũ Hành dài mười trượng do lão già tầng ba Quy Nhất tông ngưng tụ, tràn ngập sinh cơ, hấp thu cây cỏ bổ sung bổn nguyên. Bị Vương Lâm giật đứt, tàn dư hợp nhất vào áo giáp.","detail":"Cây roi dài mười trượng được lão già tầng ba dùng mộc lực Ngũ Hành hóa thành, tràn ngập sinh cơ mênh mông. Roi có khả năng hấp thu sinh cơ cây cỏ trên mặt đất để bổ sung bổn nguyên, khiến Nhân Quả ấn hút cũng không cạn. Roi là pháp bảo sở trường của Quy Nhất tông trên Tiên Cương đại lục. Trong trận đấu roi với Vương Lâm (dùng Côn Cực tiên), cây roi bị giật đứt, để lại vệt máu trên tay lão già. Tàn dư roi sau đó được lão già thu hồi hợp nhất với cơn lốc đất cát thành áo giáp.","congNang":["Hấp thu sinh cơ cây cỏ bổ sung bổn nguyên liên tục"],"chuSoHuu":[{"ten":"Lão già tóc bạc tầng ba","tuChuong":"@c1645","denChuong":"","cachCoDuoc":"Tự ngưng tụ từ mộc lực Ngũ Hành","trangThai":"hong"}],"tabs":{"tienTrinh":[{"chuong":"@c1645","loai":"xuất hiện","importance":"normal","giaiDoan":"Xuất hiện và bị phá hủy","text":"Lão già tầng ba triệu tập mộc lực Ngũ Hành hóa thành roi dài mười trượng tấn công Vương Lâm. Roi hấp thu sinh cơ cây cỏ bổ sung bổn nguyên. Bị Vương Lâm dùng Côn Cực tiên đấu roi giật đứt. Tàn dư hợp nhất vào áo giáp Quy Nhất tông.","anchor":"cây roi này tràn ngập mộc lực của Ngũ Hành, tỏa ra sinh cơ mênh mông"}]},"nguon":["@c1645"]},{"id":"ao-giap-quy-nhat-tong-moc-tho","name":"Áo giáp Quy Nhất tông (mộc + thổ)","cn":"","aliases":["Song Hành Khải"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lão già tóc bạc tầng ba"],"trangThai":"dang-dung","blurb":"Bộ áo giáp hai lực lượng Ngũ Hành mộc + thổ của Quy Nhất tông, màu vàng đất hoa văn xanh lục. Khoác vào tu vi tăng vọt từ Không Huyền trung kỳ lên Không Huyền hậu kỳ đỉnh phong, nhưng gây thống khổ phản phệ nhánh cây chui vào da thịt.","detail":"Lão già tầng ba thu hồi tàn dư roi xanh biếc hợp nhất với cơn lốc đất cát, hóa thành bộ áo giáp hai lực lượng Ngũ Hành (mộc + thổ), màu vàng đất hoa văn xanh lục. Sau khi khoác giáp, tu vi tăng vọt từ Không Huyền trung kỳ lên Không Huyền hậu kỳ đỉnh phong, chỉ cách Không Huyền đại viên mãn một bước. Tuy nhiên áo giáp gây thống khổ lớn cho người mặc: nhánh cây chui vào da thịt, áo giáp càng mạnh càng khó điều khiển, gây thương tổn. Đây là loại áo giáp đặc thù của Quy Nhất tông.","congNang":["Tăng tu vi mạnh mẽ (từ trung kỳ lên hậu kỳ đỉnh phong)","Phản phệ: nhánh cây chui vào da thịt người mặc, gây thống khổ"],"hinhDang":"Màu vàng đất, hoa văn xanh lục","vatLieu":"Tàn dư roi mộc lực + cơn lốc đất cát (mộc + thổ Ngũ Hành)","nguonGoc":"Pháp bảo đặc thù Quy Nhất tông","uyLuc":"Tăng từ Không Huyền trung kỳ lên Không Huyền hậu kỳ đỉnh phong","dacDiem":"Hai lực lượng Ngũ Hành mộc + thổ, phản phệ người dùng","chuSoHuu":[{"ten":"Lão già tóc bạc tầng ba","tuChuong":"@c1645","denChuong":"","cachCoDuoc":"Tự hợp nhất từ roi + đất cát","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1645","loai":"xuất hiện","importance":"normal","giaiDoan":"Khoác giáp tăng tu vi","text":"Lão già tầng ba hợp nhất tàn dư roi xanh biếc với cơn lốc đất cát thành áo giáp mộc + thổ. Tu vi tăng từ Không Huyền trung kỳ lên Không Huyền hậu kỳ đỉnh phong nhưng chịu phản phệ nhánh cây chui vào da thịt.","anchor":"Đây đúng là áo giáp của Quy Nhất tông!"}]},"nguon":["@c1645"]},{"id":"cay-cung-ly-quang","name":"Cây cung của Lý Quảng","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đang trong tay Vương Lâm, chưa sử dụng","blurb":"Cây cung Lý Quảng là pháp bảo do đạo nhân bảy màu trao cho Chưởng Tôn sử dụng trong trận đánh giới nội–giới ngoại Thái Cổ Tinh Thần. Sau khi Chưởng Tôn thất bại, cây cung rơi vào tay Vương Lâm và được hắn giữ lại làm hậu thủ.","detail":"Cây cung Lý Quảng vốn thuộc về Lý Quảng, được đạo nhân bảy màu (sư tôn của Chưởng Tôn) cho Chưởng Tôn mượn dùng nhằm áp đảo giới nội Thái Cổ Tinh Thần trong cuộc chiến giữa giới nội và giới ngoại. Tuy nhiên, Chưởng Tôn thất bại trong trận đánh này, cây cung đã rơi vào tay Vương Lâm; sự kiện Chưởng Tôn bẩm báo mất cây cung được ghi nhận tại @c1573. Về sau, Vương Lâm coi cây cung là một hậu thủ quan trọng, dù không muốn tùy tiện sử dụng nhưng sẵn sàng xuất ra khi lâm vào nguy cấp @c1646.","congNang":["Áp đảo giới nội Thái Cổ Tinh Thần @c1573","Được Vương Lâm giữ làm hậu thủ, dự bị sử dụng trong tình huống nguy cấp @c1646"],"chuSoHuu":[{"ten":"Lý Quảng","tuChuong":"","denChuong":"","cachCoDuoc":"Chủ gốc","trangThai":"Không rõ"},{"ten":"Vương Lâm","tuChuong":"","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"capNhatToi":"@c1646","tabs":{"tienTrinh":[{"chuong":"@c1646","loai":"nhắc tới","importance":"normal","giaiDoan":"Được Vương Lâm nhắc tới như hậu thủ chưa dùng","text":"Vương Lâm tự nhận xét còn có cây cung của Lý Quảng làm hậu thủ, dù không muốn dùng nhưng nếu nguy cấp sẽ xuất ra.","anchor":"Hắn còn có cây cung của Lý Quảng, dù không muốn dùng nhưng nếu thật sự có nguy cơ thì sẽ không do dự mà xuất ra"}]},"nguon":["@c1646"]},{"id":"song-hanh-giap","name":"Song hành giáp","aliases":["Áo giáp Quy Nhất tông (song hành)"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lão già mặc song hành khải"],"trangThai":"Bị phá hủy bởi Huyền La Đại Thiên Tôn","blurb":"Song hành giáp là bộ áo giáp cường hãn thuộc hệ trang bị của Quy Nhất tông, có khả năng tăng cường thần thông cho tu sĩ mặc nó. Tại chương @c1646, bộ giáp bị Huyền La Đại Thiên Tôn phá nát vỡ vụn như tờ giấy.","detail":"Song hành giáp là bộ áo giáp mà lão già mặc song hành khải của Quy Nhất tông mang trên người. Áo giáp này thuộc hệ thống trang bị đặc trưng của Quy Nhất tông, cho phép tu sĩ mượn lực lượng từ áo giáp để tăng cường thần thông. Dù được xưng là cường hãn, bộ giáp vẫn bị Huyền La Đại Thiên Tôn chỉ nhẹ tay vung liền phá nát vỡ vụn như tờ giấy, cho thấy khoảng cách thực lực giữa hai bên quá lớn.","congNang":["Mượn lực lượng áo giáp tăng cường thần thông cho tu sĩ Quy Nhất tông @c1646"],"chuSoHuu":[{"ten":"Lão già mặc song hành khải","tuChuong":"","denChuong":"@c1646","cachCoDuoc":"Không rõ","trangThai":"hong"}],"capNhatToi":"@c1646","tabs":{"tienTrinh":[{"chuong":"@c1646","loai":"hư tổn/tu bổ","importance":"major","giaiDoan":"Bị Huyền La Đại Thiên Tôn phá hủy","text":"Bộ song hành giáp trên người lão già bị Huyền La Đại Thiên Tôn phá nát vỡ vụn như tờ giấy.","anchor":"Song hành giáp cường hãn trên người lão già này yếu ớt giống như một tờ giấy, ầm ầm vỡ vụn"}]},"nguon":["@c1646"],"uyLuc":"Dù được coi là cường hãn, bộ song hành giáp vẫn bị Huyền La Đại Thiên Tôn phá nát vỡ vụn như tờ giấy chỉ bằng một cái vung tay @c1646.","dacDiem":"Áo giáp thuộc hệ trang bị đặc trưng của Quy Nhất tông, hoạt động theo cơ chế cho tu sĩ mượn lực lượng từ giáp để gia tăng thần thông."},{"id":"ao-giap-den-kit-tang-thap-thu-nhat","name":"Áo giáp đen kịt tầng tháp thứ nhất","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Huyền La Đại Thiên Tôn"],"trangThai":"dang-co","blurb":"Tấm áo giáp đen kịt được cất giấu trong tầng tháp thứ nhất trên Ngũ Hành tinh, bị Huyền La Đại Thiên Tôn phá sập tầng tháp đoạt lấy. Khi được lấy ra, áo giáp tỏa u quang kỳ dị, sau đó bị lực lượng ngũ hành cuốn bay về phía Huyền La rồi biến mất.","detail":"Áo giáp đen kịt là một pháp bảo được phong ấn bên trong tầng tháp thứ nhất trên Ngũ Hành tinh, vốn thuộc thế lực của Quy Nhất tông. Huyền La Đại Thiên Tôn trực tiếp phá sập tầng tháp để đoạt lấy tấm áo giáp này. Khi bị lấy ra, áo giáp lóe lên u quang tỏa ánh sáng kỳ dị, rồi bị lực lượng ngũ hành nắm lấy bay tới Huyền La và biến mất. Sau khi đoạt bảo, Huyền La tuyên bố nếu Quy Nhất tông cho rằng mình có đủ tư cách thì cứ tới lấy lại, cho thấy đây là vật có giá trị đáng kể, đủ để hai bên đại thế lực đối đầu.","congNang":["Khi kích hoạt, u quang lóe lên tỏa ánh sáng kỳ dị @c1647"],"chuSoHuu":[{"ten":"Quy Nhất tông","tuChuong":"","denChuong":"@c1647","cachCoDuoc":"Cất giấu trong tầng tháp thứ nhất","trangThai":"da-mat"},{"ten":"Huyền La Đại Thiên Tôn","tuChuong":"@c1647","denChuong":"","cachCoDuoc":"Phá tầng tháp đoạt lấy","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1647","loai":"doi-chu","importance":"major","giaiDoan":"Bị Huyền La Đại Thiên Tôn đoạt từ tầng tháp thứ nhất","text":"Huyền La Đại Thiên Tôn phá sập tầng tháp thứ nhất trên Ngũ Hành tinh, đoạt tấm áo giáp đen kịt tỏa u quang kỳ dị, tuyên bố Quy Nhất tông nếu có tư cách thì tới lấy lại.","anchor":"Tấm áo giáp đen kịt trong tầng thứ nhất bị tầng tầng sóng gợn cuốn tới, u quang lóe lên, tỏa ra ánh sáng kỳ dị"}]},"nguon":["@c1647"],"dacDiem":"Toàn thân áo giáp đen kịt, khi được lấy ra khỏi phong ấn thì phát ra u quang kỳ dị."},{"id":"ho-lu-tu-dai-chien-tuong","name":"Hồ lô khổng lồ (của tứ đại chiến tướng)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tứ đại chiến tướng"],"trangThai":"đang sử dụng","blurb":"Hồ lô khổng lồ lơ lửng trên đầu tứ đại chiến tướng, phun sương mù tạo hình Vụ thú để truy tìm hồn thứ ba của Thất Thải Tiên Tôn.","detail":"Pháp bảo của tứ đại chiến tướng, phun ra lượng lớn sương mù ngưng tụ thành Vụ thú — mãnh thú giống Kỳ Lân có khả năng đánh hơi khí tức luân hồi của hồn phách. Được dùng trong cuộc truy tìm hồn thứ ba xuyên qua Vân Hải tinh vực.","congNang":["Phun sương mù triệu hoán và nuôi dưỡng Vụ thú"],"nguon":["@c1649"]},{"id":"vu-thu","name":"Vụ thú","category":"khac","categoryLabel":"Linh thú / Công cụ truy tìm","phamCap":"Không rõ","soHuu":["Tứ đại chiến tướng"],"trangThai":"đang hoạt động","blurb":"Mãnh thú giống Kỳ Lân do sương mù từ hồ lô tạo thành, vốn là Vụ thú của Thất Thải Tiên Tôn, có khả năng đánh hơi khí tức luân hồi của hồn phách.","detail":"Mãnh thú tựa Kỳ Lân nhưng khác biệt, được tạo ra từ sương mù của hồ lô khổng lồ. Có khả năng đánh hơi khí tức luân hồi của hồn thứ ba; hấp thu càng nhiều khí tức luân hồi thì càng phán đoán chính xác vị trí mục tiêu. Tứ đại chiến tướng hủy diệt sinh mạng trên đại lục hoang phế để Vụ thú hấp thu khí tức luân hồi.","congNang":["Đánh hơi và truy tìm hồn phách qua khí tức luân hồi","Hấp thu khí tức luân hồi để tăng độ chính xác phán đoán vị trí"],"nguon":["@c1649"]},{"id":"giot-mau-huyet-mach-chung-sinh","name":"Giọt máu trong suốt (huyết mạch chúng sinh)","category":"khac","categoryLabel":"Vật phẩm truy tìm","phamCap":"Không rõ","soHuu":["Đạo nhân bảy màu"],"trangThai":"đang sử dụng","blurb":"Giọt máu trong suốt chứa huyết mạch chúng sinh, phát hồng quang khi gặp sinh linh từ ngoài động phủ giới luân hồi vào. Chỉ còn duy nhất một giọt.","detail":"Vật phẩm đặc biệt nằm trong lòng bàn tay đạo nhân bảy màu. Không phản ứng với sinh linh luân hồi bình thường trong động phủ giới; chỉ phát hồng quang chói mắt khi gặp sinh linh không phải sinh ra ở động phủ giới mà từ bên ngoài luân hồi vào. Phạm vi dò tìm không lớn, chỉ còn một giọt duy nhất nên phải dùng tiết kiệm. Đạo nhân bảy màu dùng giọt này để truy tìm hồn thứ ba của Thất Thải Tiên Tôn.","congNang":["Phát hiện sinh linh ngoại lai luân hồi vào động phủ giới bằng cách phát hồng quang"],"nguon":["@c1649"]},{"id":"hon-thu-ba-that-thai-tien-ton","name":"Hồn thứ ba (Thất Thải Tiên Tôn)","cn":"","category":"khac","categoryLabel":"Linh hồn / Bảo vật","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Hồn thứ ba của Thất Thải Tiên Tôn, tồn tại bên trong cơ thể Vương Lâm, có khả năng dẫn động các mảnh đá từ tinh không ngưng tụ thành đại môn trung tâm động phủ. Khi đại môn hình thành, cơn lốc phát ra từ nó không ảnh hưởng đến Vương Lâm nhờ hồn ở trong hắn.","detail":"Hồn thứ ba của Thất Thải Tiên Tôn nằm trong cơ thể Vương Lâm. Tại thời điểm ghi nhận, hồn thứ ba thức tỉnh và dẫn động các mảnh đá từ tinh không ngưng tụ lại, hình thành hoàn chỉnh đại môn trung tâm động phủ. Cơn lốc bùng phát từ đại môn không gây ảnh hưởng tới Vương Lâm bởi hồn đang ở bên trong hắn. Vương Lâm sau đó giơ tay phô bày hồn thứ ba trước mặt quần hùng, hồn lấp lóe u quang.","congNang":["Dẫn động các mảnh đá từ tinh không ngưng tụ thành đại môn trung tâm động phủ @c1656","Hộ chủ khỏi cơn lốc phát ra từ đại môn nhờ tồn tại bên trong cơ thể Vương Lâm @c1656"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1656","denChuong":"","cachCoDuoc":"Đã lấy được từ trước","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1656","loai":"xuất hiện","importance":"major","giaiDoan":"Phô bày trước quần hùng","text":"Hồn thứ ba thức tỉnh dẫn động đại môn trung tâm động phủ ngưng tụ hoàn chỉnh. Vương Lâm đợi quần hùng tới đủ rồi giơ tay phô bày hồn thứ ba lấp lóe u quang.","anchor":"Hồn thứ ba liền xuất hiện trong tay hắn, lấp lóe u quang"}]},"nguon":["@c1656"],"dacDiem":"Lấp lóe u quang khi được phô bày @c1656"},{"id":"doa-hoa-vang-ba-tram-tan-gioi","name":"Đóa hoa vàng năm cánh (ba trăm tàn giới)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cực phẩm (cấu trúc động phủ Thất Thải Tiên Tôn)","soHuu":["Thất Thải Tiên Tôn"],"trangThai":"còn nguyên vẹn (chủ nhân đã chết)","blurb":"Đóa hoa khổng lồ năm cánh màu vàng nằm trong đại đỉnh trung tâm động phủ của Thất Thải Tiên Tôn, lấy đất làm gốc trời làm cành lá, mang ba trăm giọt sương — mỗi giọt là một thế giới thất bại được luyện hóa thành lực phòng hộ. Do Thất Thải Tiên Tôn đã chết cùng sự xâm nhập của Liên Đạo Phi và phản bội của đệ tử, tiên phi, phòng hộ của đóa hoa đã suy yếu.","detail":"Đóa hoa vàng năm cánh là sản phẩm được luyện hóa từ ba trăm lần thất bại khi Thất Thải Tiên Tôn sáng tạo động phủ giới, nở rộ nhưng không tỏa hương, nhìn kỹ như không tồn tại. Ba trăm giọt sương trên cánh hoa chia thành ba loại: loại thứ nhất chứa tiên thú từ Tiên Cương đại lục, trải vô số năm có thể biến dị thành tồn tại cường đại; loại thứ hai chứa phàm nhân sinh sôi, Thất Thải Tiên Tôn quan sát để tìm bí mật thiên đạo; loại thứ ba không có sinh linh, pháp tắc chưa phân chia hoặc đã định sẵn. Khi chủ nhân tọa trấn, thần thức có thể tản vào ba trăm giới để thay đổi pháp tắc giới nội. Vương Lâm tiến vào đại đỉnh đã phát hiện đóa hoa này nhờ ký ức hồn thứ ba (@c1658).","hinhDang":"Đóa hoa lớn năm cánh màu vàng, lấy đất làm gốc trời làm cành lá","nguonGoc":"Ba trăm lần thất bại khi Thất Thải Tiên Tôn sáng tạo động phủ giới, được luyện hóa thành lực phòng hộ","congNang":["Phòng hộ chỗ bế quan của Thất Thải Tiên Tôn — ai không đạt tu vi tiên nhân bất diệt thể xông vào đều hao tâm tổn lực, dễ mất mạng (@c1658)","Chủ nhân tọa trấn có thể tản thần thức vào ba trăm giới, thay đổi pháp tắc giới nội"],"dacDiem":"Nở rộ nhưng không tỏa hương, nhìn kỹ như không tồn tại. Ba trăm giọt sương tương đương ba trăm thế giới, chia ba loại: chứa tiên thú có thể biến dị, chứa phàm nhân sinh sôi để quan sát thiên đạo, và giới không sinh linh với pháp tắc chưa phân chia hoặc đã định sẵn.","chuSoHuu":[{"ten":"Thất Thải Tiên Tôn","tuChuong":"@c1658","denChuong":"","cachCoDuoc":"Tự luyện hóa từ ba trăm lần thất bại","trangThai":"chủ nhân đã chết"}],"tabs":{"tienTrinh":[{"chuong":"@c1658","loai":"xuất hiện","importance":"major","giaiDoan":"Vương Lâm phát hiện","text":"Vương Lâm tiến vào đại đỉnh phát hiện đóa hoa vàng năm cánh mang ba trăm giọt sương. Nhờ ký ức hồn thứ ba của Thất Thải Tiên Tôn hiểu rõ lai lịch: mỗi giọt là một thế giới thất bại, được luyện hóa thành lực phòng hộ.","anchor":"Ba trăm lần thất bại đó Thất Thải Tiên Tôn cũng không muốn vất đi mà luyện hóa chúng"}]},"nguon":["@c1658"]},{"id":"ngoc-gian-truyen-tin-tu-ha","name":"Ngọc giản truyền tin (Tử Hà)","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Tử Hà"],"trangThai":"dang-co","blurb":"Ngọc giản dùng để truyền tin liên lạc trong tàn giới, Tử Hà lấy ra định gọi viện binh nhưng cuối cùng thu hồi vì sợ tứ đại chiến tướng đoạt mất hồn thứ ba.","detail":"Tử Hà lấy ngọc giản định bóp nát truyền tin, có thể liên lạc tứ đại chiến tướng hoặc đạo nhân bảy màu. Nàng cân nhắc rằng nếu gọi người tới thì hồn thứ ba sẽ bị đoạt, nên thu lại không dùng, quyết tâm tự mình đối phó Vương Lâm.","congNang":["Truyền tin liên lạc trong tàn giới, bóp nát để phát tín hiệu gọi viện binh"],"nguon":["@c1660"],"tabs":{"tienTrinh":[{"chuong":"@c1660","loai":"xuất hiện","importance":"normal","giaiDoan":"Tử Hà lấy ra rồi thu hồi","text":"Tử Hà lấy ngọc giản định truyền tin gọi viện binh nhưng cân nhắc rằng tứ đại chiến tướng sẽ đoạt mất hồn thứ ba nên thu lại, quyết tự mình giết Vương Lâm.","anchor":"tay phải giơ lên. Lập tức một ngọc giản liền xuất hiện, lựa chọn rời đi, truyền tin dẫn người tới nơi này"}]}},{"id":"phi-kiem-mau-tim-tu-ha","name":"Phi kiếm màu tím (Tử Hà)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tử Hà"],"trangThai":"hong","blurb":"Phi kiếm tốc độ cực nhanh của Tử Hà, bị Vương Lâm dùng sáu đạo bổn nguyên chấn nát hóa sương mù tím.","detail":"Tử Hà phóng phi kiếm màu tím thử sức Vương Lâm, tốc độ cực nhanh. Vương Lâm bộc phát sáu đạo bổn nguyên dung nhập vào ngón trỏ, một chỉ chấn nát phi kiếm, hóa thành sương mù màu tím.","congNang":["Phi kiếm tấn công tốc độ cao"],"nguon":["@c1660"],"tabs":{"tienTrinh":[{"chuong":"@c1660","loai":"dùng","importance":"normal","giaiDoan":"Bị chấn nát","text":"Tử Hà phóng phi kiếm tím thử sức Vương Lâm, bị một chỉ sáu đạo bổn nguyên chấn nát hóa sương mù tím.","anchor":"phi kiếm run rẩy liền tan nát, hóa thành sương mù màu tím cuốn đi"}]}},{"id":"phan-gioi-co-tan","name":"Phần Giới Cổ Tán","cn":"焚界古伞","aliases":["ô lửa nhỏ"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Pháp bảo hình cái ô lửa nhỏ, được Vương Lâm triệu ra bằng ấn quyết tay trái khi chuẩn bị đối phó nguy cơ trong giới cờ.","detail":"Vương Lâm tay trái bắt quyết, hỏa quang mơ hồ lóe lên hóa thành cái ô lửa nhỏ rồi biến mất. Xuất hiện cuối trận đấu giới cờ khi Vương Lâm cảm nhận nguy cơ mãnh liệt, như hậu thủ bí mật bên cạnh đại đao giới hạn.","nguon":["@c1663"]},{"id":"doa-hoa-mau-vang-khong-lo","name":"Đóa hoa màu vàng khổng lồ","cn":"","category":"khac","categoryLabel":"Kỳ bảo","phamCap":"Không rõ (kỳ bảo từ tiên giới)","soHuu":["Thất Thải Tiên Tôn"],"trangThai":"dang-co","blurb":"Kỳ bảo do Thất Thải Tiên Tôn mang về từ tiên giới, không sở hữu lực công kích nhưng tràn ngập sinh cơ kinh người, là nguồn sống duy trì sự tồn tại của ba trăm tàn giới.","detail":"Đóa hoa màu vàng khổng lồ là một kỳ bảo được Thất Thải Tiên Tôn lấy từ tiên giới. Tuy hoàn toàn không có lực công kích, pháp bảo này lại chứa đựng sinh cơ kinh người, đóng vai trò cốt lõi trong việc cung cấp dưỡng chất duy trì sự tồn tại của ba trăm tàn giới. Bí mật về đóa hoa chỉ nằm trong ký ức của Thất Thải Tiên Tôn, ngay cả tiên phi và tứ đại chiến tướng đều không hay biết. Nếu không có Liên Đạo Phi xuất hiện, Thất Thải Tiên Tôn sẽ không rơi vào thế chật vật.","nguonGoc":"Thất Thải Tiên Tôn lấy từ tiên giới","congNang":["Tràn ngập sinh cơ kinh người, cung cấp dưỡng chất duy trì sự tồn tại của ba trăm tàn giới @c1665","Chữa thương với tốc độ tăng rất nhiều"],"chuSoHuu":[{"ten":"Thất Thải Tiên Tôn","tuChuong":"@c1665","denChuong":"","cachCoDuoc":"Lấy từ tiên giới","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1665","loai":"xuất hiện","importance":"major","giaiDoan":"Hé lộ bí mật nguồn sống ba trăm tàn giới","text":"Hé lộ đóa hoa kỳ bảo từ tiên giới là nguồn duy trì sự tồn tại của ba trăm tàn giới, bí mật chỉ Thất Thải Tiên Tôn biết.","anchor":"Kỳ bảo này không có lực công kích nhưng lại tràn ngập sinh cơ kinh người"}]},"nguon":["@c1665"]},{"id":"hon-thu-ba-vuong-lam","name":"Hồn thứ ba (Vương Lâm)","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Hồn thứ ba của Vương Lâm, về sự hùng mạnh còn kém đạo nhân bảy màu và Chiến lão quỷ rất xa nhưng là khát vọng cả đời của họ.","detail":"Vương Lâm lấy từ mi tâm ra, để lơ lửng trên đỉnh đầu một trượng, phóng thích toàn bộ khí tức làm mồi nhử dẫn dụ các cường giả vào bẫy Phần Giới Cổ Tán.","nguon":["@c1667"]},{"id":"chien-huong","name":"Chiến hương","aliases":["thiên hương"],"category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Hương liệu đặc biệt phát tín hiệu triệu tập hoặc dẫn dụ đệ tử Thất Đạo Tông.","detail":"Vương Lâm đốt chiến hương phát ra mùi hương khiến toàn bộ đệ tử Thất Đạo Tông ở giới ngoại đồng loạt hành động tìm tới vị trí của mình.","nguon":["@c1667"]},{"id":"truong-thuong-bay-mau","name":"Trường thương bảy màu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Vương Lâm","Đạo nhân bảy màu"],"trangThai":"da-dung","blurb":"Trường thương bảy màu là vũ khí năng lượng dạng trường thương mang sắc bảy màu, được cả Vương Lâm và đạo nhân bảy màu thi triển trong trận đối chiến. Hai thanh trường thương va chạm gây chấn động kinh thiên động địa rồi cùng tan vỡ; uy lực khi phát huy hơn nửa lực lượng được mô tả là cực kỳ kinh người.","detail":"Trong trận chiến với đạo nhân bảy màu, Vương Lâm thi triển trường thương bảy màu từ mặt đất lao ra như rồng gào thét, mang sắc bảy màu, phá tan hoàn toàn đài sen bảy màu của đối thủ — các cánh hoa lần lượt vỡ nát và đài sen nổ tung. Đạo nhân bảy màu lập tức triệu ra một thanh trường thương bảy màu y hệt để đối chọi; hai thương va chạm gây chấn động kinh thiên động địa rồi cùng tan vỡ. Thuật này khi phát huy hơn nửa lực lượng thì uy lực cực kỳ kinh người.","congNang":["Xung kích cực mạnh dạng trường thương, có thể phá tan đài sen bảy màu khiến các cánh hoa lần lượt vỡ và đài sen nổ tung @c1668","Cả hai bên đối chiến đều có thể thi triển thanh trường thương y hệt nhau để đối chọi @c1668"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1668","denChuong":"","cachCoDuoc":"Thi triển","trangThai":"da-dung"},{"ten":"Đạo nhân bảy màu","tuChuong":"@c1668","denChuong":"","cachCoDuoc":"Thi triển","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1668","loai":"dung","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Vương Lâm tung ra phá tan đài sen bảy màu. Đạo nhân bảy màu triệu thanh y hệt đối chọi, hai thương cùng vỡ.","anchor":"một thanh trường thương bảy màu trong một tiếng thét kinh thiên của Vương Lâm từ trong mặt đất bên cạnh Vương Lâm trực tiếp lao ra"}]},"nguon":["@c1668"],"uyLuc":"Hai thanh trường thương bảy màu va chạm gây chấn động kinh thiên động địa rồi cùng tan vỡ; khi thuật phát huy hơn nửa lực lượng thì uy lực cực kỳ kinh người @c1668","dacDiem":"Từ mặt đất lao ra như rồng gào thét, mang sắc bảy màu @c1668"},{"id":"vong-tron-do-mau","name":"Vòng tròn đỏ máu","cn":"","category":"phap-bao","categoryLabel":"Cấm chế / Trận pháp tạm","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Cấm chế do Vương Lâm dùng máu tươi vẽ ra từ trước, ẩn giấu cấm chế bên trong, nổ tung bao vây đạo nhân bảy màu phối hợp kích thích Mục Ngư.","detail":"Vương Lâm dùng máu tươi vẽ vòng tròn đỏ bên ngoài thân thể từ trước. Khi đệ lục phục kích hoạt, vòng tròn lao lên không trung, cấm chế tiêu tan, máu tươi và thiên địa nguyên khí bộc phát nổ tung, khí tức bao vây đạo nhân bảy màu ngay khi hắn vừa tỉnh khỏi cơn sợ Thiên Đạo.","congNang":["Bao vây mục tiêu bằng khí tức, phối hợp kích hoạt Mục Ngư biến dị"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1668","denChuong":"","cachCoDuoc":"Tự vẽ bằng máu tươi","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1668","loai":"dung","importance":"normal","giaiDoan":"Kích hoạt trong đệ lục phục","text":"Vòng tròn máu lao lên không trung nổ tung bao vây đạo nhân bảy màu phối hợp Mục Ngư thức tỉnh.","anchor":"vòng tròn đỏ như máu mà Vương Lâm dùng máu tươi để vẽ ra ở bên ngoài thân thể lúc trước lập tức ầm ầm lao lên không trung"}]},"nguon":["@c1668"]},{"id":"muc-ngu","name":"Mục Ngư","cn":"","category":"khac","categoryLabel":"Linh thú đặc thù","phamCap":"Không rõ","soHuu":["Vương Lâm","Huyền La Đại Thiên Tôn"],"trangThai":"chia-doi","blurb":"Mục Ngư là chín linh ngư do Thất Thải Tiên Tôn nuôi dưỡng trong ba trăm tàn giới. Đặc tính nổi bật nhất là đôi trống mái khí tức tương liên, có thể liên lạc xuyên không gian ngay cả khi bị thu vào không gian trữ vật. Vương Lâm thu được ba con, Huyền La Đại Thiên Tôn thu sáu con.","detail":"Chín con Mục Ngư được Thất Thải Tiên Tôn nuôi dưỡng bên trong ba trăm tàn giới. Khi bị phát hiện, chúng bị chia làm hai phần: Huyền La Đại Thiên Tôn thu được sáu con, Vương Lâm thu được ba con. Đặc tính cốt lõi của Mục Ngư nằm ở cơ chế trống mái thành đôi — hai con một đôi có khí tức tương liên, nhờ đó có thể liên lạc xuyên không gian bất kể cách trở, kể cả khi bị thu vào không gian trữ vật. Liên kết này chỉ đứt khi một trong hai con tử vong.","congNang":["Đôi trống mái khí tức tương liên, có thể liên lạc xuyên không gian dù bị cách trở hay bị thu vào không gian trữ vật @c1671","Liên kết chỉ mất hiệu lực khi một trong hai con tử vong @c1671"],"nguonGoc":"Do Thất Thải Tiên Tôn nuôi dưỡng trong ba trăm tàn giới","chuSoHuu":[{"ten":"Thất Thải Tiên Tôn","tuChuong":"@c1671","denChuong":"","cachCoDuoc":"Nuôi dưỡng","trangThai":"da-mat"},{"ten":"Vương Lâm","tuChuong":"@c1671","denChuong":"","cachCoDuoc":"Thu trong ba trăm giới sụp đổ (3 con)","trangThai":"dang-co"},{"ten":"Huyền La Đại Thiên Tôn","tuChuong":"@c1671","denChuong":"","cachCoDuoc":"Thu trước Vương Lâm (6 con)","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1671","loai":"xuat-hien","importance":"major","giaiDoan":"Bị tranh cướp giữa Vương Lâm và Huyền La Đại Thiên Tôn","text":"Chín con Mục Ngư trong ba trăm tàn giới bị chia: Huyền La Đại Thiên Tôn thu sáu con (năm con biến mất trước + con thứ tư trước mắt Vương Lâm), Vương Lâm thu ba con. Hé lộ đặc tính đôi trống mái khí tức tương liên liên lạc xuyên không gian.","anchor":"hai con trống mái thì được gọi là một đôi, khí tức tương liên, dù có bị thu vào trong không gian trữ vật"}]},"nguon":["@c1671"],"dacDiem":"Vốn chín con, trống mái thành đôi, khí tức tương liên bất kể khoảng cách và không gian ngăn cách; liên kết chỉ đứt khi một con chết."},{"id":"tam-than-huyet-diep-mich","name":"Tâm thần huyết Diệp Mịch","cn":"","category":"nguyen-lieu","categoryLabel":"Tinh huyết / Bảo vật","phamCap":"Không rõ","soHuu":["Vân Na"],"trangThai":"phong-an","blurb":"Tâm thần huyết cuối cùng của Diệp Mịch, ẩn chứa trong cơ thể Vân Na. Có thể dung hợp để chữa thương hoàn toàn.","detail":"Máu huyết tâm thần cuối cùng của Diệp Mịch, được cất giữ trong cơ thể nữ Cổ Thần Vân Na tại đệ nhị hoa Ngũ hoa bát môn. Vân Na đề nghị Vương Lâm dung hợp để chữa thương.","congNang":["Dung hợp để chữa thương hoàn toàn"],"chuSoHuu":[{"ten":"Vân Na","tuChuong":"@c1671","denChuong":"","cachCoDuoc":"Ẩn chứa trong cơ thể","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1671","loai":"xuat-hien","importance":"normal","giaiDoan":"Được Vân Na tiết lộ","text":"Vân Na tiết lộ cơ thể nàng ẩn chứa tâm thần huyết cuối cùng của Diệp Mịch, đề nghị Vương Lâm dung hợp để chữa thương.","anchor":"trong cơ thể của ta có tâm thần huyết cuối cùng của Diệp Mịch"}]},"nguon":["@c1671"]},{"id":"nguyen-than-huyet-diep-mich-giot-cuoi","name":"Nguyên thần huyết Diệp Mịch (giọt cuối cùng)","cn":"","category":"khac","categoryLabel":"Huyết mạch","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Giọt nguyên thần huyết cuối cùng của Diệp Mịch, do nữ Cổ Thần từ mi tâm ngưng tụ ra trao cho Vương Lâm. Sau khi hấp thu, toàn bộ nguyên thần huyết Diệp Mịch trên người Vương Lâm được hoàn thiện trọn vẹn, thương thế khôi phục hoàn toàn, xương cốt và Đạo cổ lực đều được tăng cường.","detail":"Nữ Cổ Thần điểm vào mi tâm, ngưng tụ giọt nguyên thần huyết cuối cùng của Diệp Mịch rồi trao cho Vương Lâm. Đây là giọt nguyên thần huyết then chốt giúp hoàn thiện toàn bộ nguyên thần huyết Diệp Mịch vốn đã tích lũy trên người Vương Lâm. Sau khi hấp thu, thương thế của Vương Lâm khôi phục hoàn toàn, xương cốt trở nên chắc chắn hơn, Đạo cổ lực mạnh mẽ hơn trước. Đồng thời, việc nguyên thần huyết được hoàn chỉnh cũng kích hoạt nguyên thần Diệp Mịch ngưng tụ, mưu đoạt xá thân Vương Lâm nhưng thất bại.","congNang":["Hoàn thiện toàn bộ nguyên thần huyết Diệp Mịch trên người Vương Lâm @c1672","Khôi phục thương thế Vương Lâm hoàn toàn @c1672","Tăng cường độ chắc chắn của xương cốt @c1672","Tăng cường Đạo cổ lực @c1672","Kích hoạt nguyên thần Diệp Mịch ngưng tụ mưu đoạt xá (thất bại) @c1672"],"chuSoHuu":[{"ten":"Vân Na","tuChuong":"@c1672","denChuong":"@c1672","cachCoDuoc":"Ngưng tụ từ mi tâm","trangThai":"da-trao"},{"ten":"Vương Lâm","tuChuong":"@c1672","denChuong":"","cachCoDuoc":"Được nữ Cổ Thần trao","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1672","loai":"đổi chủ","importance":"major","giaiDoan":"Trao và hấp thu","text":"Nữ Cổ Thần ngưng tụ giọt nguyên thần huyết cuối cùng từ mi tâm trao cho Vương Lâm. Vương Lâm hấp thu, nguyên thần huyết Diệp Mịch hoàn toàn đầy đủ, thương thế khôi phục. Nguyên thần Diệp Mịch ngưng tụ mưu đoạt xá thất bại, tiêu tán vĩnh viễn.","anchor":"Hấp thu nguyên thần huyết của Diệp Mịch, thương thế của ngươi sẽ khôi phục"}]},"nguon":["@c1672"],"uyLuc":"Hoàn thiện trọn vẹn nguyên thần huyết Diệp Mịch, giúp Vương Lâm khôi phục hoàn toàn thương thế đồng thời tăng cường cả xương cốt lẫn Đạo cổ lực.","dacDiem":"Là giọt nguyên thần huyết cuối cùng, được nữ Cổ Thần ngưng tụ từ mi tâm; khi hấp thu sẽ hoàn chỉnh toàn bộ nguyên thần huyết Diệp Mịch và kích hoạt nguyên thần Diệp Mịch ẩn trong huyết."},{"id":"canh-tay-trai-diep-mich","name":"Cánh tay trái Diệp Mịch","cn":"","category":"khac","categoryLabel":"Bộ phận thân thể Cổ Thần","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"Đã dung hợp","blurb":"Cánh tay trái của Cổ Thần Diệp Mịch, bị phong ấn trong hồ băng Đông Lâm Trì, được Vương Lâm phá băng và dung hợp thành công. Kết hợp với cánh tay phải Diệp Mịch đã có trước đó, uy lực thuật Tê Thiên tăng vượt bậc, khi dung hợp tỏa u quang bao phủ mấy vạn dặm.","detail":"Cánh tay trái khổng lồ của Cổ Thần Diệp Mịch, phong ấn trong tầng băng sâu tại Đông Lâm Trì. Hồ băng đã dung hợp với cánh tay nên có lực tự phục hồi khi bị phá, khiến Vương Lâm phải vận dụng Đạo Cổ bất diệt chỉ suốt mấy canh giờ mới phá nổi lớp băng. Khi lớp băng bị phá, lộ ra da tay màu tro tàn, tỏa khí tức Đạo Cổ nồng đậm. Vương Lâm đặt tay trái lên cánh tay và hấp thu trong ba ngày, cánh tay thu nhỏ hóa làn khói chui vào tay hắn, hoàn tất dung hợp. Cánh tay trái kết hợp với cánh tay phải Diệp Mịch đã có trước đó, khiến uy lực thuật Tê Thiên tăng mạnh, vượt xa mức xé tan thân thể tu sĩ bước thứ ba. Lúc dung hợp, u quang tỏa ra bao phủ mấy vạn dặm.","congNang":["Tăng cường uy lực thuật Tê Thiên khi kết hợp với cánh tay phải Diệp Mịch, vượt xa mức xé tan thân thể tu sĩ bước thứ ba @c1673"],"hinhDang":"Cánh tay trái khổng lồ, da màu tro tàn","nguonGoc":"Bộ phận thân thể của Cổ Thần Diệp Mịch, phong ấn trong Đông Lâm Trì","dacDiem":"Da tay màu tro tàn, tỏa khí tức Đạo Cổ nồng đậm; khi dung hợp tỏa u quang bao phủ mấy vạn dặm.","chuHienThoi":"Vương Lâm","boCha":"hon-thu-ba-vuong-lam","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1673","denChuong":"","cachCoDuoc":"Phá băng Đông Lâm Trì rồi dung hợp","trangThai":"da-dung-hop"}],"tabs":{"tienTrinh":[{"chuong":"@c1673","loai":"xuat hien","importance":"major","giaiDoan":"Phát hiện và dung hợp","text":"Vương Lâm cảm ứng sự kêu gọi từ sâu trong tầng băng, bay tới Đông Lâm Trì phát hiện cánh tay trái Diệp Mịch phong ấn dưới hồ băng. Phá băng suốt mấy canh giờ bằng Đạo Cổ bất diệt chỉ, lộ da tay, hấp thu ba ngày dung hợp thành công — cánh tay hóa làn khói chui vào tay hắn.","anchor":"cánh tay trái hóa thành một làn khói chui vào trong tay Vương Lâm"}]},"nguon":["@c1673"],"uyLuc":"Kết hợp hai cánh tay Diệp Mịch, uy lực thuật Tê Thiên vượt xa mức xé tan thân thể tu sĩ bước thứ ba."},{"id":"khoi-bang-dong-lam-tri","name":"Khối băng Đông Lâm Trì","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"Thu giữ","blurb":"Khối băng giật từ hồ Đông Lâm Trì, chứa lực lượng giống bổn nguyên, hỏa bổn nguyên không thể hòa tan.","detail":"Vương Lâm giật khối băng lớn từ hồ Đông Lâm Trì khi phá tầng băng, phát hiện bên trong chứa một tia lực lượng giống bổn nguyên. Dùng hỏa bổn nguyên thử hòa tan nhưng không được. Thu vào không gian trữ vật, phát ra hàn khí như thủy tinh. Từ đó suy đoán Đông Lâm Trì thật trên Tiên Cương đại lục có công hiệu nuôi dưỡng bổn nguyên.","congNang":["Chứa lực lượng giống bổn nguyên, khả năng nuôi dưỡng bổn nguyên"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1673","denChuong":"","cachCoDuoc":"Giật từ hồ băng Đông Lâm Trì","trangThai":"dang-co"}],"nguon":["@c1673"]},{"id":"chuoi-hat-chau-tren-co-tay-de-tam-phi","name":"Chuỗi hạt châu trên cổ tay đệ tam phi","cn":"","aliases":["Hạt châu màu vàng (Đường San)"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Đường San"],"trangThai":"đang sử dụng","blurb":"Bảo vật do sư tôn đệ tam phi ban tặng, đeo trên cổ tay, có thể hóa thành bảy kim môn đồng thời hiện ra.","detail":"Chuỗi hạt châu trên cổ tay đệ tam phi Đường San, do sư tôn nàng ban tặng. Có thể hóa thành bảy kim môn đồng thời hiện ra, uy lực lớn hơn kim môn đơn lẻ. Đệ tam phi đề nghị dùng vật này giúp Vương Lâm tiến vào ngọn núi nơi Dĩ Ti Chi Khôi ẩn náu.","nguonGoc":"Sư tôn đệ tam phi ban tặng","congNang":["Hóa thành bảy kim môn đồng thời hiện ra"],"chuSoHuu":[{"ten":"Đường San","tuChuong":"@c1675","denChuong":"","cachCoDuoc":"Sư tôn ban tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1675","loai":"xuất hiện","importance":"normal","giaiDoan":"Đệ tam phi đưa ra đề nghị giúp Vương Lâm","text":"Đệ tam phi đưa ra chuỗi hạt châu trên cổ tay — bảo vật sư tôn ban tặng, có thể hóa thành bảy kim môn đồng thời — đề nghị giúp Vương Lâm tiến vào ngọn núi nơi Dĩ Ti Chi Khôi ẩn náu.","anchor":"có thể hóa thành bảy kim môn đồng thời hiện ra"}]},"nguon":["@c1675"]},{"id":"the-huyet-van-dat-phong","name":"Thệ huyết Vân Dật Phong","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Vài giọt thệ huyết từ mi tâm Vân Dật Phong đưa cho Vương Lâm làm tin. Sau khi thua trận, thệ huyết phát hồng quang biến mất trong lòng bàn tay Vương Lâm, hoá thành lời thề ràng buộc.","detail":"Vân Dật Phong vỗ mi tâm lấy ra vài giọt thệ huyết đưa cho Vương Lâm trước trận đấu. Khi Vân Dật Phong thừa nhận thua, thệ huyết phát hồng quang chói mắt, chậm rãi biến mất trong lòng bàn tay Vương Lâm, trở thành lời thề ràng buộc.","nguon":["@c1676"]},{"id":"kim-an-phap-bao-thuc-chat","name":"Kim ấn (pháp bảo thực chất)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Kim ấn vốn là thần thông hư ảo do Chưởng Tôn ngưng tụ bằng máu vàng ở tầng ba Chưởng diệt tam đạo, bị Huyền La chỉ tay biến thành pháp bảo thực chất lơ lửng trước Vương Lâm. Công năng cụ thể chưa được thể hiện, pháp bảo mới vừa sinh ra tại thời điểm ghi nhận.","detail":"Trong cuộc đối đầu giữa Chưởng Tôn và Huyền La, Chưởng Tôn phun máu vàng ngưng tụ thành kim ấn hư ảo — đây là biểu hiện của tầng thứ ba trong Chưởng diệt tam đạo, tức Đệ tam diệt thần đạo. Tuy nhiên, Huyền La chỉ tay dừng kim ấn giữa không trung rồi biến hóa nó từ dạng hư ảo sang pháp bảo thực chất. Kim ấn sau khi chuyển hóa hóa lớn, lơ lửng trước mặt Vương Lâm, phát ra tiếng vù vù như đang run rẩy thần phục. Nguồn gốc của nó vừa là thần thông của Chưởng Tôn, vừa mang dấu ấn biến hóa của Huyền La, song công năng chiến đấu hay tác dụng cụ thể chưa được bộc lộ tại thời điểm ghi nhận.","congNang":["Chưa rõ — mới vừa sinh ra từ thần thông bị biến hóa"],"nguonGoc":"Ngưng tụ từ máu vàng Chưởng Tôn (tầng ba Chưởng diệt tam đạo), bị Huyền La biến thành thực chất","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1677","denChuong":"","cachCoDuoc":"Huyền La biến kim ấn thần thông của Chưởng Tôn thành pháp bảo rồi để trước mặt Vương Lâm","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1677","loai":"xuất hiện","importance":"major","giaiDoan":"Sinh ra từ thần thông","text":"Kim ấn vốn là thần thông hư ảo do Chưởng Tôn thi triển, bị Huyền La chỉ tay biến thành pháp bảo thực chất lơ lửng trước Vương Lâm, phát tiếng vù vù thần phục.","anchor":"Vật này nhìn đúng là thực chất, mà còn là một pháp bảo!"}]},"nguon":["@c1677"],"dacDiem":"Nguyên là thần thông hư ảo được ngưng tụ từ máu vàng Chưởng Tôn, sau khi bị Huyền La biến thành thực chất thì hóa lớn lơ lửng, phát tiếng vù vù như run rẩy thần phục (@c1677)."},{"id":"kim-an-huyen-la","name":"Kim ấn (Huyền La sáng tạo)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (bảo vật vô chủ)","soHuu":["Vương Lâm"],"trangThai":"dang-dung","blurb":"Kim ấn là pháp bảo do Huyền La Đại Thiên Tôn sáng tạo từ hư ảo, Vương Lâm trở thành chủ nhân đầu tiên sau khi tu vi rơi vào ấn. Bảo vật này phong ấn Diệt Thần Đạo Thuật của Chưởng Tôn, đồng thời ẩn chứa một tia cửu dương lực do Huyền La tạo ra, không thể phá vỡ.","detail":"Kim ấn được Huyền La Đại Thiên Tôn sáng tạo từ hư ảo, vốn là bảo vật vô chủ. Tu vi của Vương Lâm rơi vào ấn khiến hắn trở thành chủ nhân đầu tiên. Sau khi nhận chủ, Vương Lâm nuốt kim ấn vào miệng, tế luyện bên trong nguyên thần. Kim ấn mang trong mình công dụng phong ấn Diệt Thần Đạo Thuật của Chưởng Tôn; ngoài ra bên trong còn ẩn chứa một tia cửu dương lực do Huyền La tạo ra, lực lượng này không thể phá vỡ. Khi xuất hiện, kim ấn tỏa hào quang vạn trượng.","nguonGoc":"Huyền La Đại Thiên Tôn sáng tạo từ hư ảo","hinhDang":"Kim ấn tỏa hào quang vạn trượng, lạnh băng","congNang":["Phong ấn Diệt Thần Đạo Thuật của Chưởng Tôn @c1678","Ẩn chứa một tia cửu dương lực do Huyền La tạo ra, không thể phá vỡ @c1678"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1678","denChuong":"","cachCoDuoc":"Nhận chủ bảo vật vô chủ do Huyền La sáng tạo","trangThai":"dang-co"}],"capNhatToi":"@c1678","tabs":{"tienTrinh":[{"chuong":"@c1678","loai":"xuất hiện","importance":"major","giaiDoan":"Được sáng tạo và nhận chủ","text":"Huyền La sáng tạo kim ấn từ hư ảo, Vương Lâm nhận chủ trở thành chủ nhân đầu tiên, nuốt vào tế luyện trong nguyên thần. Kim ấn phong ấn Diệt Thần Đạo Thuật của Chưởng Tôn, chứa cửu dương lực.","anchor":"vật này vừa từ trong hư ảo được sáng tạo ra, vẫn còn là một bảo vật vô chủ"}]},"nguon":["@c1678"],"uyLuc":"Tỏa hào quang vạn trượng, nội chứa cửu dương lực không thể phá vỡ.","dacDiem":"Bảo vật được sáng tạo từ hư ảo, vô chủ cho đến khi Vương Lâm nhận chủ; có thể nuốt vào miệng tế luyện trong nguyên thần."},{"id":"truong-mau-do-ti","name":"Trường mâu (Đồ Ti)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thác Sâm"],"trangThai":"dang-dung","blurb":"Thanh trường mâu khổng lồ được Đồ Ti (trong thân Thác Sâm) triệu từ hư không, dùng chiến đấu với Chưởng Tôn.","detail":"Đồ Ti sau khi thức tỉnh trong thân Thác Sâm, triệu thanh trường mâu khổng lồ trực tiếp hiện ra trong tay, đâm về phía Chưởng Tôn. Khí thế phá vỡ hết thảy. Bị Chưởng Tôn tay trái túm lấy.","congNang":["Vũ khí chiến đấu tầm xa, khí thế phá vỡ hết thảy"],"chuSoHuu":[{"ten":"Thác Sâm","tuChuong":"@c1678","denChuong":"","cachCoDuoc":"Triệu từ hư không khi Đồ Ti thức tỉnh","trangThai":"dang-co"}],"capNhatToi":"@c1678","tabs":{"tienTrinh":[{"chuong":"@c1678","loai":"xuất hiện","importance":"normal","giaiDoan":"Đồ Ti triệu trường mâu chiến đấu","text":"Đồ Ti thức tỉnh trong thân Thác Sâm, triệu thanh trường mâu khổng lồ từ hư không đâm Chưởng Tôn, bị Chưởng Tôn túm lấy.","anchor":"một thanh trường mâu khổng lồ trực tiếp hiện ra ở trong tay hắn"}]},"nguon":["@c1678"]},{"id":"co-cam-lam-mong","name":"Cổ cầm của Lam Mộng Đạo Tôn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo","soHuu":["Lam Mộng Đạo Tôn"],"trangThai":"dang-co","blurb":"Cổ cầm chí bảo phong ấn nhiều năm trong máu Lam Mộng Đạo Tôn, lai lịch thần bí, mơ hồ không phải vật của động phủ giới. Cả đời hắn mới dùng một lần, tiếng đàn hóa sát khí phong tỏa đối thủ, tỏa khí tức tang thương, là nguyên nhân chính khiến Chưởng Tôn kiêng kỵ hắn trong thái cổ ngũ tôn.","detail":"Cổ cầm vô hình, phong ấn nhiều năm trong máu Lam Mộng Đạo Tôn, phải phun máu dung hợp lam quang mới có thể triệu ra. Lai lịch cực kỳ thần bí, mơ hồ không phải vật của động phủ giới. Đây là đòn sát thủ cuối cùng của Lam Mộng Đạo Tôn, cả đời mới dùng một lần — cuộc chiến thành danh được ví là 'một bản đàn chôn vạn cốt, quay đầu đã ngàn năm'. Tâm tư tiêu hao để tế luyện cổ cầm còn nhiều hơn cả độ Huyền Kiếp. Cổ cầm chính là nguyên nhân khiến Chưởng Tôn kiêng kỵ Lam Mộng Đạo Tôn trong hàng ngũ thái cổ ngũ tôn. Khi triệu ra, tiếng đàn tỏa khí tức tang thương, hóa sát khí phong tỏa bốn phía đối thủ.","congNang":["Phong ấn trong máu chủ nhân, phun máu dung hợp lam quang mới triệu ra @c1681","Tiếng đàn hóa sát khí, phong tỏa không gian bốn phía mục tiêu @c1681","Tỏa khí tức tang thương khi được triệu ra @c1681"],"hinhDang":"Cổ cầm, vốn vô hình khi phong ấn","nguonGoc":"Lai lịch thần bí, mơ hồ không phải vật của động phủ giới","dacDiem":"Phong ấn trong máu chủ nhân, tỏa khí tức tang thương khi triệu ra; lai lịch thần bí, mơ hồ không phải vật của động phủ giới.","chuHienThoi":"Lam Mộng Đạo Tôn","chuSoHuu":[{"ten":"Lam Mộng Đạo Tôn","tuChuong":"@c1681","denChuong":"","cachCoDuoc":"Không rõ, phong ấn nhiều năm trong máu","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1681","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu lộ diện","text":"Lam Mộng Đạo Tôn phun máu dung hợp lam quang triệu cổ cầm chí bảo phong ấn nhiều năm trong máu. Tiếng đàn hóa sát khí phong tỏa bốn phía Chiến lão quỷ. Là nguyên nhân Chưởng Tôn kiêng kỵ hắn nhất trong thái cổ ngũ tôn.","anchor":"Cả đời Lam Mộng Đạo Tôn mới chỉ dùng cổ cầm này một lần"}]},"nguon":["@c1681"],"uyLuc":"Cả đời chỉ dùng một lần, cuộc chiến thành danh được ví là 'một bản đàn chôn vạn cốt, quay đầu đã ngàn năm'; tâm tư tế luyện tiêu hao còn nhiều hơn độ Huyền Kiếp, là nguyên nhân chính khiến Chưởng Tôn phải kiêng kỵ Lam Mộng Đạo Tôn."},{"id":"dao-bao-xanh-the-gioi-ky-uc","name":"Đạo bào màu xanh (thế giới ký ức)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Đạo bào Vương Lâm mặc trong thế giới ký ức đệ ngũ hoa, tỏa thanh quang, có lực phòng hộ chống được một đòn toàn lực tu sĩ vấn Đỉnh.","detail":"Đạo bào xanh xuất hiện trên người Vương Lâm khi hắn hóa thành hình dạng Tô Đạo trong thế giới đệ ngũ hoa. Tỏa thanh quang, có lực phòng hộ có thể chống cự một đòn toàn lực của tu sĩ vấn Đỉnh.","congNang":["Phòng hộ chống đòn toàn lực tu sĩ vấn Đỉnh"],"nguon":["@c1684"]},{"id":"hai-dao-phong-an-ta-thanh","name":"Hai đạo phong ấn Tạ Thanh","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đã sử dụng","blurb":"Hai đạo phù văn phong ấn do Tạ Thanh xả thân ngưng tụ trước khi chết, bên trong chứa tâm huyết và ánh mắt bi phẫn của nàng. Sau khi dung hợp khí tức Tiên Cương đại lục, phong ấn được Vương Lâm kích hoạt nhằm phong ấn hồn phách Thất Thải Tiên Tôn.","detail":"Tạ Thanh — luân hồi hồn thứ ba của Thất Thải Tiên Tôn — đã xả thân ngưng tụ ba đạo phong ấn trước khi chết: một đạo dành cho bản thân, hai đạo giao lại Vương Lâm. Phong ấn chứa toàn bộ tâm huyết cùng ánh mắt bi phẫn cuối cùng của Tạ Thanh, cần dung hợp khí tức Tiên Cương đại lục mới có thể hoạt hóa hoàn toàn. Tại chương @c1690, Vương Lâm kích hoạt hai đạo phong ấn, dung hợp khí tức Tiên Cương và phóng ra nhắm vào lưỡng hồn Thất Thải Tiên Tôn. Khi kích hoạt, phong ấn như số mệnh xuyên qua mọi thần thông, không gì ngăn cản nổi — khắc lên mi tâm lưỡng hồn Thất Thải Tiên Tôn, biến chúng thành quả cầu ánh sáng cỡ nắm tay, cắt đứt liên hệ giữa hồn phách này với Chiến lão quỷ.","congNang":["Phong ấn hồn phách Thất Thải Tiên Tôn, khắc lên mi tâm lưỡng hồn, biến chúng thành quả cầu ánh sáng cỡ nắm tay @c1690","Xuyên qua mọi thần thông như số mệnh, không thể ngăn cản @c1690","Cắt đứt liên hệ giữa hồn phách Thất Thải Tiên Tôn với Chiến lão quỷ @c1690"],"nguonGoc":"Tạ Thanh xả thân ngưng tụ trước khi chết","dacDiem":"Cần dung hợp khí tức Tiên Cương đại lục mới hoạt hóa; chứa tâm huyết và ánh mắt bi phẫn cuối cùng của Tạ Thanh khi xả thân ngưng tụ.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1690","denChuong":"","cachCoDuoc":"Tạ Thanh giao trước khi chết","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1690","loai":"dùng","importance":"major","giaiDoan":"Kích hoạt phong ấn lưỡng hồn Thất Thải","text":"Vương Lâm kích hoạt hai đạo phong ấn, dung hợp khí tức Tiên Cương, phóng ra phong ấn lưỡng hồn Thất Thải Tiên Tôn thành hai quả cầu ánh sáng, cắt đứt liên hệ với Chiến lão quỷ.","anchor":"Tạ Thanh lấy thân là một lần luân hồi của hồn thứ ba xả thân vì đại nghiệp, ngưng tụ ra ba đạo phong ấn"}]},"nguon":["@c1690"],"uyLuc":"Phong ấn như số mệnh xuyên qua mọi thần thông, không gì ngăn cản, khắc lên mi tâm lưỡng hồn Thất Thải Tiên Tôn biến thành quả cầu ánh sáng, cắt đứt liên hệ với Chiến lão quỷ."},{"id":"chiec-thuyen-khong-lo-buom-mat-quy","name":"Chiếc thuyền khổng lồ (buồm mặt quỷ)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Chiếc thuyền khổng lồ của Phàn San Lộ, tấm buồm mặt quỷ đã bị Vương Lâm luyện hóa chủ cấm. Phàn San Lộ rời đi để lại, Vương Lâm thu vào không gian trữ vật.","detail":"Chiếc thuyền khổng lồ do Phàn San Lộ (Nhất Phi của Thất Thải Tiên Tôn) để lại khi rời động phủ giới. Tấm buồm mặt quỷ trên thuyền đã bị Vương Lâm luyện hóa chủ cấm nên có thể điều khiển tự nhiên. Vương Lâm thu vào không gian trữ vật.","nguon":["@c1694"],"congNang":["Thuyền di chuyển, buồm mặt quỷ là bộ phận chủ cấm đã bị Vương Lâm luyện hóa @c1694"],"chuSoHuu":[{"ten":"Phàn San Lộ","tuChuong":"","denChuong":"@c1694","cachCoDuoc":"Sở hữu ban đầu","trangThai":"da-roi"},{"ten":"Vương Lâm","tuChuong":"@c1694","denChuong":"","cachCoDuoc":"Phàn San Lộ rời đi để lại","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1694","loai":"doi-chu","importance":"normal","giaiDoan":"Phàn San Lộ rời đi, Vương Lâm thu nhận","text":"Phàn San Lộ rời động phủ giới về quê hương, để lại chiếc thuyền khổng lồ. Buồm mặt quỷ đã bị Vương Lâm luyện hóa chủ cấm nên điều khiển tự nhiên, Vương Lâm thu vào không gian trữ vật.","anchor":"Vật này vốn đã bị Vương Lâm luyện hóa chủ cấm là tấm buồm mặt quỷ"}]},"capNhatToi":"@c1694"},{"id":"thanh-kiem-bon-nguyen","name":"Thanh kiếm bổn nguyên","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Mộc Băng Mi"],"trangThai":"binh-thuong","blurb":"Kiếm do Vương Lâm ngưng tụ từ bảy đạo bổn nguyên dung hợp khí tức Đạo Cổ, uy lực kinh người, tặng cho Mộc Băng Mi trước lúc ly biệt.","detail":"Vương Lâm ngưng tụ bảy đạo bổn nguyên trong cơ thể thành thanh kiếm ánh sáng, dung hợp khí tức Đạo Cổ. Kiếm này uy lực kinh người, được Vương Lâm tặng cho Mộc Băng Mi trước khi rời đi.","congNang":["Dung hợp lực lượng bổn nguyên và khí tức Đạo Cổ, uy lực kinh người"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1695","denChuong":"@c1695","cachCoDuoc":"Tự ngưng tụ bổn nguyên","trangThai":"da-tang"},{"ten":"Mộc Băng Mi","tuChuong":"@c1695","denChuong":"","cachCoDuoc":"Vương Lâm tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1695","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm tạo kiếm tặng Mộc Băng Mi","text":"Vương Lâm ngưng tụ bảy đạo bổn nguyên thành thanh kiếm dung hợp khí tức Đạo Cổ, tặng cho Mộc Băng Mi trước khi rời Tiên Giới.","anchor":"Kiếm này dung hợp lực lượng bổn nguyên của Vương Lâm, cũng tràn ập khí tức Đạo Cổ, uy lực kinh người!"}]},"nguon":["@c1695"]},{"id":"long-tien-huyet-sac","name":"Long tiên huyết sắc","cn":"","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Cực phẩm (lực lượng Không Kiếp trung kỳ)","soHuu":["Huyền La"],"trangThai":"binh-thuong","blurb":"Long tiên huyết sắc là một trong cửu binh Long Hoàng thiên nhất của Huyền La, cây roi dài trăm trượng luyện từ hồn phách và xương cốt con rồng có lực Không Kiếp trung kỳ ở vùng man hoang phía đông Tiên Cương đại lục. Huyền La dùng cây roi này phá quy tắc thiên địa Tiên Cương đại lục, mở lỗ hổng cho chuyển thế đầu thai, uy lực khiến Vương Lâm cảm thấy bản thân cũng không chịu nổi.","detail":"Tại vùng man hoang phía đông Tiên Cương đại lục, Huyền La tìm được một con rồng có sừng hình vương miện, lân phiến tím đậm, thân dài mấy vạn trượng, sở hữu lực lượng Không Kiếp trung kỳ. Huyền La giết con rồng, lấy hồn phách luyện lại thân thể nó, xương cốt tế thành binh khí — cây roi huyết sắc dài trăm trượng, tức Long tiên huyết sắc. Đây là một trong cửu binh Long Hoàng thiên nhất mà Huyền La triệu hoán bằng cách bắt quyết @c1695. Huyền La sử dụng cây roi này phá vỡ quy tắc của Tiên Cương đại lục, mở ra lỗ hổng trong thiên địa để mọi người chuyển thế đầu thai. Vương Lâm chứng kiến uy lực cây tiên, kinh hãi cảm thấy bản thân cũng không thể chịu nổi.","phanLoaiPhu":"Roi (long tiên)","hinhDang":"Khi triệu hoán hiện nguyên hình rồng thân mấy vạn trượng, sừng hình vương miện, lân phiến tím đậm; thu nhỏ thành cây roi huyết sắc dài trăm trượng","vatLieu":"Hồn phách và xương cốt con rồng Không Kiếp trung kỳ","nguonGoc":"Huyền La giết con rồng ở vùng man hoang phía đông Tiên Cương đại lục, lấy hồn phách luyện lại thân thể, xương cốt tế thành binh khí","uyLuc":"Sở hữu lực lượng Không Kiếp trung kỳ, uy lực khiến Vương Lâm cảm thấy bản thân cũng không chịu nổi.","dacDiem":"Cây roi huyết sắc dài trăm trượng, luyện từ hồn phách và xương cốt con rồng sừng hình vương miện, lân phiến tím đậm, thân dài mấy vạn trượng; là một trong cửu binh Long Hoàng thiên nhất của Huyền La.","chuHienThoi":"Huyền La","congNang":["Phá quy tắc Tiên Cương đại lục, mở lỗ hổng trong thiên địa cho chuyển thế đầu thai @c1695"],"chuSoHuu":[{"ten":"Huyền La","tuChuong":"@c1695","denChuong":"","cachCoDuoc":"Tự luyện chế từ con rồng man hoang","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1695","loai":"xuất hiện","importance":"major","giaiDoan":"Huyền La triệu hoán long tiên chuẩn bị phá quy tắc Tiên Cương","text":"Huyền La bắt quyết triệu hoán Long Hoàng thiên nhất — con rồng sừng hình vương miện, lân phiến tím đậm, thân mấy vạn trượng lao ra từ dòng xoáy, thu nhỏ thành cây roi huyết sắc dài trăm trượng. Huyền La tuyên bố dùng cây long tiên phá quy tắc Tiên Cương đại lục, mở lỗ hổng thiên địa.","anchor":"Đây là một trong cửu binh Long Hoàng thiên nhất của lão phu, tìm được từ vùng man hoang phía đông của Tiên Cương đại lục."}]},"nguon":["@c1695"]},{"id":"hoang-long-tien","name":"Hoàng Long Tiên","cn":"黄龙鞭","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Đại nhất linh","soHuu":["Huyền La"],"trangThai":"dang-dung","blurb":"Hoàng Long Tiên là đại nhất linh trong bốn đại linh của Huyền La, cây tiên có thể hóa dài mấy vạn trượng như cự long, xé tan sương mù mở con đường chuyển thế hình mình rồng thông tới Tiên Cương đại lục.","detail":"Hoàng Long Tiên là pháp bảo đầu tiên được Huyền La triệu hồi trong bốn đại linh. Khi thi triển, Huyền La vung Hoàng Long Tiên chín nhát, cây tiên gào thét hóa thành dài mấy vạn trượng, xé tan sương mù trong đại môn động phủ, mở ra con đường hình mình rồng thông tới Tiên Cương đại lục, con đường ấy tựa như đường luân hồi. Đây là pháp bảo giữ vai trò khai lộ chuyển thế trong trận chiến của Huyền La.","congNang":["Hóa dài mấy vạn trượng như hình cự long khi được vung chín nhát @c1696","Xé tan sương mù trong đại môn động phủ, mở ra con đường chuyển thế hình mình rồng thông tới Tiên Cương đại lục @c1696"],"hinhDang":"Cây tiên, hóa dài mấy vạn trượng","chuSoHuu":[{"ten":"Huyền La","tuChuong":"@c1696","denChuong":"","cachCoDuoc":"Sở hữu sẵn","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1696","loai":"dung","importance":"major","giaiDoan":"Mở con đường chuyển thế","text":"Huyền La vung Hoàng Long Tiên chín nhát, cây tiên hóa dài mấy vạn trượng xé sương mù đại môn động phủ, mở ra con đường mình rồng thông tới Tiên Cương.","anchor":"chỉ thấy cây tiên kia bắt đầu gào thét, trực tiếp quất về phía đại môn của động phủ"}]},"nguon":["@c1696"],"uyLuc":"Vung chín nhát xé tan sương mù đại môn động phủ, khai mở con đường chuyển thế hình mình rồng thông tới Tiên Cương đại lục, tựa như đường luân hồi.","dacDiem":"Khi thi triển gào thét hóa dài mấy vạn trượng như cự long, là đại nhất linh trong bốn đại linh của Huyền La."},{"id":"son-yeu","name":"Sơn Yêu","cn":"山妖","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Đại nhị linh","soHuu":["Huyền La"],"trangThai":"dang-dung","blurb":"Đại nhị linh của Huyền La, yêu tiên luyện từ ngọn núi vạn năm ở Tiên Cương, ngưng tụ sơn hồn tế thành. Khi triệu hồi, Sơn Yêu tán ra phủ băng trắng toàn bộ con đường mình rồng, bảo vệ hồn phách người chuyển thế không bị tiêu tan trước mê chướng.","detail":"Huyền La luyện hóa một ngọn núi vạn năm ở Tiên Cương, ngưng tụ vô số sơn hồn mà tế thành yêu tiên, gọi là Sơn Yêu, xếp vào hàng đại nhị linh. Khi được triệu hồi, Sơn Yêu tán ra lớp phủ băng trắng bao phủ toàn bộ con đường mình rồng, giữ cho hồn phách của người đang chuyển thế không bị mê chướng xâm thực tiêu tan.","congNang":["Phủ băng trắng lên toàn bộ con đường mình rồng, bảo vệ hồn phách người chuyển thế không bị tiêu tan trước mê chướng @c1696"],"nguonGoc":"Ngọn núi vạn năm ở Tiên Cương, ngưng tụ sơn hồn tế thành yêu tiên","chuSoHuu":[{"ten":"Huyền La","tuChuong":"@c1696","denChuong":"","cachCoDuoc":"Tự luyện hóa","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1696","loai":"dung","importance":"major","giaiDoan":"Bảo vệ con đường chuyển thế","text":"Huyền La triệu hồi Sơn Yêu phủ băng trắng lên toàn bộ con đường mình rồng, bảo vệ hồn phách người chuyển thế không tiêu tan trước mê chướng.","anchor":"sơn yêu này là do lão phu đã luyện hóa một ngọn núi vạn năm ở Tiên Cương"}]},"nguon":["@c1696"]},{"id":"phong-ma","name":"Phong Ma","cn":"封魔","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Đại tứ linh","soHuu":["Huyền La"],"trangThai":"dang-dung","blurb":"Phong Ma là pháp bảo do Huyền La tế luyện suốt ba lần chuyển thế, thu 36 triệu tà niệm của kẻ chí hung chí ác ngưng tụ thành, một trong ba binh khí mạnh nhất của Huyền La tại Đạo Cổ nhất mạch. Pháp bảo mang hình thái ma ảnh sương đen, có linh trí riêng gọi là ma linh, giữ vai trò phong ấn toàn bộ con đường chuyển thế và bảo toàn ký ức người chuyển thế không sứt mẻ.","detail":"Phong Ma là ma ảnh sương đen, được Huyền La tế luyện suốt ba lần chuyển thế, thu ba mươi sáu triệu tà niệm của kẻ chí hung chí ác mà ngưng tụ thành, sở hữu linh trí riêng biệt gọi là ma linh. Đây là một trong ba binh khí mạnh nhất của Huyền La tại Đạo Cổ nhất mạch. Tại mốc @c1696, Huyền La cắn lưỡi phun máu hóa thành Phong Ma, phong ấn toàn bộ con đường chuyển thế, bảo toàn ký ức và che giấu thân phận kiếp trước. Pháp bảo này hoạt động như chiếc ấn phong tỏa tuyệt đối, giữ cho ký ức qua các lần chuyển thế không sứt mẻ, và chỉ sau khi được điểm hóa mới khôi phục toàn bộ trí nhớ cho chủ nhân.","congNang":["Phong ấn toàn bộ con đường chuyển thế, bảo toàn ký ức người chuyển thế không sứt mẻ @c1696","Che giấu thân phận kiếp trước của người chuyển thế @c1696","Sau khi được điểm hóa sẽ khôi phục toàn bộ trí nhớ cho chủ nhân"],"nguonGoc":"Tế luyện suốt 3 lần chuyển thế, thu 36 triệu tà niệm của kẻ chí hung chí ác ngưng tụ thành","dacDiem":"Ma ảnh sương đen có linh trí riêng gọi là ma linh, một trong ba binh khí mạnh nhất của Huyền La tại Đạo Cổ nhất mạch, được tế luyện từ 36 triệu tà niệm của kẻ chí hung chí ác ngưng tụ thành.","hinhDang":"Ma ảnh sương đen","chuSoHuu":[{"ten":"Huyền La","tuChuong":"@c1696","denChuong":"","cachCoDuoc":"Tự tế luyện","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1696","loai":"dung","importance":"major","giaiDoan":"Phong ấn ký ức con đường chuyển thế","text":"Huyền La cắn lưỡi phun máu hóa thành Phong Ma, phong ấn toàn bộ con đường chuyển thế, bảo toàn ký ức và che giấu thân phận kiếp trước cho mọi người.","anchor":"Ma này đã được lão phu tế luyện suốt ba lần chuyển thế, theo năm tháng vô tận đã thu được ba mươi sáu triệu tà niệm"}]},"nguon":["@c1696"]},{"id":"mat-troi-dai-thien-ton-luc","name":"Mặt trời Đại Thiên Tôn lực","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Đại Thiên Tôn","soHuu":["Huyền La","Vương Lâm"],"trangThai":"da-mat","blurb":"Mặt trời đỏ như máu do Huyền La dùng Cửu Dương Đại Thiên Tôn lực tạo ra, biến thần thông vô hình thành vật thật, khuếch đại Mộng Đạo Thuật vô hạn, tự hủy sau khi dùng.","detail":"Huyền La nắm tay rồi buông, tạo ra mặt trời đỏ như máu to bằng nắm tay từ Cửu Dương Đại Thiên Tôn lực, vật chất hóa thần thông vô hình thành thực thể có thể chạm cầm cảm nhận. Trao cho Vương Lâm để mở rộng ý cảnh Mộng Đạo Thuật vô hạn, phong ấn ký ức mọi người vào trong mộng. Sau khi Vương Lâm thi triển xong, mặt trời vỡ vụn tiêu tan.","congNang":["Khuếch đại ý cảnh Mộng Đạo Thuật vô hạn","Biến thần thông vô hình thành vật thật"],"dacDiem":"Dùng một lần rồi tự hủy","chuSoHuu":[{"ten":"Huyền La","tuChuong":"@c1696","denChuong":"@c1696","cachCoDuoc":"Tự tạo bằng Đại Thiên Tôn lực","trangThai":"da-trao"},{"ten":"Vương Lâm","tuChuong":"@c1696","denChuong":"@c1696","cachCoDuoc":"Huyền La trao","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1696","loai":"dung","importance":"normal","giaiDoan":"Trao cho Vương Lâm khuếch đại Mộng Đạo","text":"Huyền La tạo mặt trời Đại Thiên Tôn lực trao cho Vương Lâm, khuếch đại Mộng Đạo Thuật gần mức mộng thành thực. Sau khi dùng xong thì vỡ vụn tiêu tan.","anchor":"lập tức liền có mặt trời đỏ như máu từ trong lòng bàn tay hắn nối lên"}]},"nguon":["@c1696"]},{"id":"huyet-long-mau-cuu-duong","name":"Huyết long (máu Cửu Dương của Huyền La)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Máu tươi Cửu Dương do Huyền La phun ra hóa thành con huyết long, cuốn lấy Vương Lâm bảo hộ dọc đường đối phó pháp tắc Tiên Cương, đồng thời mang ý nghĩa lễ bái sư giữa hai người. Huyết long duy trì hiệu lực trong mười năm.","detail":"Tại thời điểm Vương Lâm chuẩn bị tiến vào Tiên Cương, Huyền La vỗ mi tâm rồi cắn đầu lưỡi phun ra một ngụm máu tươi Cửu Dương; máu phát ra hồng quang lập tức hóa thành hình con huyết long, cuốn chặt lấy Vương Lâm và đưa hắn lao vào lỗ hổng trên lớp băng dẫn vào hư vô. Máu Cửu Dương này mang song trùng ý nghĩa: một là nghi thức bái sư, xác lập quan hệ sư đồ giữa Huyền La và Vương Lâm; hai là phương tiện bảo hộ, giúp Vương Lâm chống chọi pháp tắc Tiên Cương suốt hành trình, với thời hạn hiệu lực kéo dài mười năm.","congNang":["Hóa hình huyết long cuốn lấy Vương Lâm, bảo hộ dọc đường chống lại pháp tắc Tiên Cương, duy trì hiệu lực mười năm @c1699","Đóng vai trò lễ bái sư, xác lập quan hệ sư đồ giữa Huyền La và Vương Lâm @c1699"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1699","denChuong":"","cachCoDuoc":"Huyền La phun máu hóa huyết long cuốn lấy khi bái sư","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1699","loai":"xuat-hien","importance":"major","giaiDoan":"Tạo ra khi bái sư","text":"Huyền La vỗ mi tâm phun máu tươi Cửu Dương hóa huyết long cuốn Vương Lâm lao vào hư vô, vừa làm lễ bái sư vừa bảo hộ dọc đường đối phó pháp tắc Tiên Cương, duy trì mười năm.","anchor":"cắn đầu lười phun ra một ngụm máu tươi. Máu tươi của hắn phát ra hồng quang, hóa thành một con huyết long"}]},"nguon":["@c1699"]},{"id":"qua-cau-hon-phach-bi-an","name":"Quả cầu ánh sáng (chứa hồn phách bí ẩn)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hoàng tôn Đạo Cổ nhất mạch"],"trangThai":"dang-co","blurb":"Quả cầu ánh sáng trong tay hoàng tôn Đạo Cổ nhất mạch, bên trong chứa một hồn phách bí ẩn đang ngủ say. Theo lời quốc sư, hồn phách này có tiềm năng giúp người sở hữu nắm cả Tiên Cương đại lục.","detail":"Quả cầu lóe u quang, rắn chắc, xuất hiện trong tay hoàng tôn Đạo Cổ nhất mạch tại hoàng cung. Bên trong chứa một hồn phách nho nhỏ đang ngủ say, có biểu hiện run rẩy sợ hãi khi hoàng tôn nắm mạnh — cho thấy hồn phách có tri giác nhất định dù đang trong trạng thái ngủ. Quốc sư Đạo Cổ nhất mạch khẳng định hồn phách này có thể giúp hoàng tôn nắm cả Tiên Cương đại lục, song cần tìm một nữ tử phù hợp để dung hợp với hồn phách. Hoàng tôn gọi việc tìm nữ tử dung hợp này là lập hậu, cho thấy quả cầu và hồn phách bên trong đóng vai trò trung tâm trong mưu đồ chính trị của Đạo Cổ nhất mạch.","congNang":["Chứa và duy trì hồn phách trong trạng thái ngủ say, hồn phách có tri giác và phản ứng với tác động bên ngoài @c1700","Hồn phách bên trong được cho là có thể giúp nắm cả Tiên Cương đại lục khi dung hợp với nữ tử phù hợp (theo lời quốc sư) @c1700"],"chuSoHuu":[{"ten":"Hoàng tôn Đạo Cổ nhất mạch","tuChuong":"@c1700","denChuong":"","cachCoDuoc":"Không rõ (có từ khi lộ diện)","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1700","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện tại hoàng cung Đạo Cổ","text":"Hoàng tôn Đạo Cổ nhất mạch cầm quả cầu chứa hồn phách ngủ say tại hoàng cung. Quyết định tìm nữ tử dung hợp với hồn phách theo lời quốc sư, ra lệnh Diệp Đạo thực hiện.","anchor":"Một hồn phách nho nhỏ mà vì sao quốc sư lại nói nó có thể giúp ta nắm cả Tiên Cương đại lục"}]},"nguon":["@c1700"],"dacDiem":"Quả cầu lóe u quang, rắn chắc; hồn phách bên trong tuy đang ngủ say nhưng có tri giác, biểu hiện run rẩy sợ hãi khi bị nắm mạnh."},{"id":"hai-cot-bach-quang","name":"Hài cốt bạch quang","category":"khac","categoryLabel":"Di vật kỳ dị","phamCap":"Không rõ","soHuu":[],"trangThai":"da-dung","blurb":"Hài cốt lão già mặc tử bào trôi trong hư vô, chết nhưng vẫn tỏa bạch quang, trong lồng ngực ngưng tụ sức mạnh kỳ dị lạnh lẽo.","detail":"Vương Lâm ấn tay lên ngực thi thể, hút bạch quang cùng sức mạnh kỳ dị vào cơ thể; sức mạnh này lạnh lẽo khiến đầu óc tỉnh táo, khôi phục bổn nguyên héo rũ và cả một phần sức mạnh Đạo Cổ. Đây là thi thể thứ hai Vương Lâm gặp; mười năm trong hư vô hắn chỉ gặp hai thi thể như vậy.","congNang":["Khôi phục bổn nguyên héo rũ và tu vi Đạo Cổ @c1702"],"dacDiem":"Tỏa bạch quang dù đã chết; sức mạnh lạnh lẽo khiến đầu óc tỉnh táo","capNhatToi":"@c1702","tabs":{"tienTrinh":[{"chuong":"@c1702","loai":"dùng","importance":"normal","text":"Vương Lâm hút bạch quang và sức mạnh kỳ dị từ thi thể thứ hai để khôi phục bổn nguyên cùng sức mạnh Đạo Cổ.","anchor":"trên người hắn lại lan ra bạch quang"}]},"nguon":["@c1702"]},{"id":"dai-cao-hinh-canh-cung","name":"Đài cao hình cánh cung","cn":"","category":"khac","categoryLabel":"Di tích Tiên Cương","phamCap":"Không rõ (vượt Đại Thiên Tôn)","soHuu":[],"trangThai":"đã hóa thành thân xác đá","blurb":"Đài cao hình cánh cung vạn trượng trôi dạt trong hư vô Tiên Cương, phát hào quang màu trăng, là di tích nơi tổ tiên chín loài thú kỳ dị được sinh ra. Được bao bọc bởi vách ngăn pháp tắc Tiên Cương mà chỉ Tiên Tổ, Cổ Tổ và chín loài thú kỳ dị mới có thể dung nhập; khi hấp thụ giọt máu Vương Lâm cùng bạch quang, đài hóa thành thân xác đá khổng lồ tạo phân thân mạnh nhất cho Vương Lâm.","detail":"Đài cao vạn trượng hình cánh cung, vị trí không cố định, trôi dạt trong hư vô của Tiên Cương. Bản thân đài phát ra hào quang màu trăng tương đồng với bạch quang từng xuất hiện trên những thi thể đặc biệt, cho thấy mối liên hệ sâu xa với pháp tắc Tiên Cương. Xung quanh đài tồn tại vách ngăn vô hình do pháp tắc Tiên Cương ngưng tụ; ngay cả cường giả như Huyền La cũng rất khó xâm nhập, duy chỉ Tiên Tổ, Cổ Tổ — những tồn tại tự thân sinh ra pháp tắc Tiên Cương — và chín loài thú kỳ dị đồng bạn mới có thể dung nhập qua lớp rào chắn này. Đài chính là nơi tổ tiên của Văn Thú được sinh ra, mang ý nghĩa khởi nguồn đối với chín loài thú kỳ dị. Tại mốc @c1703, Văn Thú Vương lần theo manh mối tìm được đài cao trong hư vô và hi sinh gần hết thân thể để đưa giọt máu tươi từ tim Vương Lâm xuyên qua vách ","congNang":["Hấp thụ giọt máu tươi mang bạch quang pháp tắc Tiên Cương, sau đó hút bạch quang từ khắp hư vô Tiên Cương, tự biến hình từ đài đá thành thân xác đá khổng lồ, bên trong huyết khí dung hợp bạch quang ngưng tụ hư ảnh — tạo phân thân cho chủ nhân giọt máu (@c1703)"],"dacDiem":"Vị trí không cố định, trôi dạt trong hư vô Tiên Cương; phát hào quang màu trăng; bao quanh bởi vách ngăn vô hình do pháp tắc Tiên Cương ngưng tụ — chỉ Tiên Tổ, Cổ Tổ và chín loài thú kỳ dị mới dung nhập được.","nguonGoc":"Di tích pháp tắc Tiên Cương, nơi tổ tiên chín loài thú kỳ dị được sinh ra","tabs":{"tienTrinh":[{"chuong":"@c1703","loai":"xuat-hien","importance":"major","giaiDoan":"Hấp thụ máu Vương Lâm, hóa thân xác đá tạo phân thân","text":"Văn Thú Vương tìm được đài cao trong hư vô, hi sinh gần hết thân thể đưa giọt máu tươi từ tim Vương Lâm qua vách ngăn. Đài hấp thụ giọt máu, chấn động hút bạch quang khắp hư vô, mềm ra hóa thành thân xác bằng đá khổng lồ, bên trong ngưng tụ hư ảnh Vương Lâm.","anchor":"dần dần trở nên mềm mại, bên rìa nhô lên, giống như là một bàn tay người đang nắm lại... trở thành một thân xác bằng đá khổng lồ"}]},"capNhatToi":"@c1703","nguon":["@c1703"]},{"id":"xac-da-phan-than-vuong-lam","name":"Xác đá chứa phân thân Vương Lâm","cn":"","category":"khac","categoryLabel":"Kỳ vật","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Xác đá trôi nổi trong hư vô, bên trong chứa phân thân Vương Lâm đang trưởng thành theo pháp tắc Tiên Cương đại lục. Phân thân này chính là nguyên nhân khiến bổn tôn Vương Lâm tỉnh lại và khôi phục toàn bộ tu vi, được hắn coi như long mạch phong thủy và quyết để phân thân tự phá xác đi ra.","detail":"Bên trong xác đá có phân thân Vương Lâm đang trưởng thành trong pháp tắc Tiên Cương, tương tự xác đá khi tổ tiên Văn Thú được sinh ra. Xác đá tồn tại lực phản chấn mãnh liệt, cự tuyệt mọi đụng chạm hay xâm nhập từ bên ngoài. Khi Vương Lâm phát hiện xác đá tại @c1704, hắn ngộ ra toàn bộ quá trình khôi phục tu vi của mình thực chất là nhờ phân thân bên trong đang không ngừng trưởng thành — phân thân lớn mạnh thì bổn tôn càng cường đại. Hắn liên hệ nguyên lý này với thuyết phong thủy long mạch, coi phân thân là mạch nguồn bồi dưỡng bổn tôn, và quyết định không can thiệp mà để phân thân tự nhiên phá xác đi ra.","congNang":["Nuôi dưỡng phân thân Vương Lâm trong pháp tắc Tiên Cương; phân thân trưởng thành thì bổn tôn theo đó cường đại, là nguồn gốc khiến Vương Lâm khôi phục toàn bộ tu vi @c1704","Sinh ra lực phản chấn cự tuyệt mọi đụng chạm và xâm nhập từ bên ngoài @c1704"],"tabs":{"tienTrinh":[{"chuong":"@c1704","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ công năng, Vương Lâm quyết để nguyên","text":"Vương Lâm phát hiện phân thân đang trưởng thành trong xác đá, xác nhận tu vi khôi phục là nhờ phân thân. Chạm vào bị lực phản chấn hất ra. Liên hệ phong thủy long mạch, quyết định bỏ ý phá xác đá, để phân thân chờ cơ duyên trưởng thành hoàn toàn.","anchor":"một luồng lực phản chấn từ trên xác đá lan ra, lập tức hất bắn tay hắn lên"}]},"nguon":["@c1704"]},{"id":"khong-gian-tru-vat-vuong-lam","name":"Không Gian trữ vật của Vương Lâm","category":"khac","categoryLabel":"Khác","soHuu":["Vương Lâm"],"trangThai":"bất ổn","blurb":"Không gian trữ vật của Vương Lâm, rất bất ổn trong hư vô như sắp sụp đổ, không dám mở. Bên trong chứa nhiều đan dược, pháp bảo, cùng người điên và ngân y nữ tử.","detail":"Khi ở trong hư vô dẫn vào Tiên Cương, không gian này cực kỳ bất ổn, Vương Lâm không dám mở vì sợ nổ tung, không chắc vào Tiên Cương rồi còn tồn tại hay không. Bên trong có người điên và ngân y nữ tử — hai người có huyết mạch Tiên Cương nên dù xảy ra bất trắc cũng không sao.","congNang":["Trữ vật phẩm, đan dược, pháp bảo","Chứa được người sống (người điên, ngân y nữ tử)"],"tabs":{"tienTrinh":[{"chuong":"@c1705","loai":"nhắc tới","importance":"normal","giaiDoan":"Bất ổn trong hư vô","text":"Rất bất ổn như sắp sụp đổ trong hư vô, Vương Lâm không dám mở, bên trong chứa nhiều đan dược, pháp bảo, người điên và ngân y nữ tử.","anchor":"Lần trước khi mở Không Gian trữ vật hắn thấy không gian đó rất bất ồn, giống như sắp sụp đổ."}]},"nguon":["@c1705"]},{"id":"kim-an-dai-thien-ton","name":"Kim ấn Đại Thiên Tôn","cn":"","aliases":["Kim ấn","Pháp Bảo Đại Thiên Tôn"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"bi-ket-trong-khong-gian-tru-vat","blurb":"Di vật chứa thần thông của sư tôn Thất Thải đạo nhân cô đọng lại, mang sức mạnh một đòn đánh cấp Không Kiếp sơ kỳ. Đang bị kẹt trong Không Gian trữ vật.","detail":"Kim ấn được thần thông sư tôn Thất Thải đạo nhân cô đọng lại, chứa một kích cường lực ngang tu sĩ Không Kiếp sơ kỳ. Nằm trong danh sách pháp bảo quan trọng Vương Lâm cần lấy ra từ Không Gian trữ vật.","congNang":["Một đòn đánh cấp Không Kiếp sơ kỳ (dùng một lần)"],"nguonGoc":"Sư tôn Thất Thải đạo nhân ban tặng","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1711","denChuong":"","cachCoDuoc":"Sư tôn ban","trangThai":"bi-ket-trong-khong-gian"}],"tabs":{"tienTrinh":[{"chuong":"@c1711","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị kẹt trong Không Gian trữ vật","text":"Vương Lâm nhắc tới kim ấn chứa thần thông sư tôn cô đọng, sức mạnh ngang tu sĩ Không Kiếp sơ kỳ, cần lấy ra từ Không Gian trữ vật.","anchor":"Còn có kim ấn được thần thông sư tôn cô đọng lại. Vật ấy là một kích của tu sĩ Không Kiếp sơ kỳ"}]},"nguon":["@c1711"]},{"id":"di-ti-khoi-loi","name":"Dĩ Ti khôi lỗi","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Ngang Không Kiếp","soHuu":["Vương Lâm"],"trangThai":"bi-ket-trong-khong-gian-tru-vat","blurb":"Khôi lỗi của Vương Lâm, sức mạnh có thể sánh ngang Không Kiếp. Đang bị kẹt trong Không Gian trữ vật tại Tiên Cương đại lục.","detail":"Dĩ Ti khôi lỗi có sức mạnh sánh ngang Không Kiếp, nằm trong danh sách pháp bảo quan trọng Vương Lâm cần lấy ra từ Không Gian trữ vật.","congNang":["Sức mạnh chiến đấu ngang Không Kiếp"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1711","denChuong":"","cachCoDuoc":"","trangThai":"bi-ket-trong-khong-gian"}],"tabs":{"tienTrinh":[{"chuong":"@c1711","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị kẹt trong Không Gian trữ vật","text":"Vương Lâm nhắc tới Dĩ Ti khôi lỗi, sức mạnh sánh ngang Không Kiếp, cần lấy ra từ Không Gian trữ vật.","anchor":"Còn cả Dĩ Ti khôi lỗi. Vật đó có thể so với không kiếp"}]},"nguon":["@c1711"]},{"id":"khong-gian-tru-vat-moi-co-tay","name":"Không Gian trữ vật mới (cổ tay phải)","cn":"","category":"khac","categoryLabel":"Trữ vật","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đang dùng","blurb":"Không Gian trữ vật mới được Vương Lâm tạo trên cổ tay phải theo phương pháp của Tiên Cương đại lục, mở bằng huyết mạch cơ thể, thay thế Không Gian trữ vật cũ để phục vụ chiến đấu.","detail":"Tại chương @c1712, Vương Lâm vận dụng phương pháp đặc thù của Tiên Cương đại lục để tạo một Không Gian trữ vật mới ngay trên cổ tay phải. Khi kích hoạt bằng huyết mạch cơ thể, một khe tối đen lan ra lực hút, cho phép thu nạp pháp bảo vào bên trong. Phương pháp này chỉ có nhân tài Tiên Cương đại lục mới thực hiện được hoàn mỹ. Sau khi tạo thành, Vương Lâm thu Huyết Kiếm và kim ấn Đại Thiên Tôn vào không gian mới, đồng thời luyện tập thuần thục thao tác để tránh mở nhầm khe trữ vật cũ trong lúc chiến đấu.","congNang":["Trữ vật trên cơ thể, kích hoạt mở ra bằng huyết mạch cơ thể @c1712","Khi mở tạo khe tối đen lan ra lực hút để thu nạp vật phẩm @c1712","Thu chứa pháp bảo như Huyết Kiếm và kim ấn Đại Thiên Tôn @c1712"],"nguonGoc":"Phương pháp Tiên Cương đại lục","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1712","denChuong":"","cachCoDuoc":"Tự tạo","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1712","loai":"xuất hiện","importance":"major","giaiDoan":"Tạo mới","text":"Vương Lâm tạo Không Gian trữ vật mới trên cổ tay phải theo phương pháp Tiên Cương đại lục, dùng huyết mạch cơ thể mở ra, thu Huyết Kiếm và kim ấn vào.","anchor":"Lấy huyết mạch của cơ thể mở ra Không Gian trữ vật, phương pháp kiếu này cũng chỉ có nhân tài trên Tiên Cương đại lục mới có thể làm được một cách hoàn mỹ"}]},"nguon":["@c1712"]},{"id":"than-the-khoi-loi-go-do-thanh","name":"Thân thể khôi lỗi gỗ của Đỗ Thanh","cn":"","category":"khac","categoryLabel":"Khôi lỗi / Thân ngoại","phamCap":"","soHuu":["Đỗ Thanh"],"trangThai":"dang-co","blurb":"Thân thể khôi lỗi gỗ của Đỗ Thanh là hình thái nguyên bản của hắn, bên trong chứa một tia trọng bổn nguyên giúp chủ nhân minh ngộ bổn nguyên này. Khi lao vào chiến đấu, toàn thân Đỗ Thanh vặn vẹo lộ nguyên hình thành khôi lỗi gỗ bốc lửa.","detail":"Đỗ Thanh vốn mang thân thể khôi lỗi gỗ — hình dạng toàn thân vặn vẹo kỳ dị. Khi giao chiến với Vương Lâm, hắn lộ nguyên hình, toàn thân hóa thành khôi lỗi gỗ bốc lửa (@c1717). Bên trong thân khôi lỗi chứa một tia trọng bổn nguyên; nhờ mang thân thể này mà Đỗ Thanh dần tìm hiểu và minh ngộ được trọng bổn nguyên. Trong quá trình tu đạo, cũng chính nhờ thân khôi lỗi mà hắn từng trải qua đủ chuyện kỳ dị.","congNang":["Chứa một tia trọng bổn nguyên, giúp chủ nhân từ từ tìm hiểu và minh ngộ trọng bổn nguyên (@c1717)","Bốc lửa khi chủ nhân lao vào chiến đấu, toàn thân vặn vẹo lộ nguyên hình khôi lỗi gỗ (@c1717)"],"tabs":{"tienTrinh":[{"chuong":"@c1717","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ nguyên hình khôi lỗi gỗ","text":"Đỗ Thanh lộ thân khôi lỗi gỗ bốc lửa khi lao vào chiến đấu với Vương Lâm. Lộ rằng thân khôi lỗi chứa một tia trọng bổn nguyên là căn nguyên giúp hắn minh ngộ và được Đại Hồn Môn che chở.","anchor":"thân thể khôi lỗi của hắn lại có một tia trọng bổn nguyên, lúc đó mới giúp hắn từ từ tìm hiểu ra"}]},"nguon":["@c1717"],"dacDiem":"Hình thái nguyên bản của Đỗ Thanh, toàn thân vặn vẹo thành khôi lỗi gỗ, bốc lửa khi giao chiến."},{"id":"ngoc-gian-ban-do-thien-nguu-chau","name":"Ngọc giản bản đồ Thiên Ngưu Châu","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang sử dụng","blurb":"Bản đồ đầy đủ Thiên Ngưu Châu được ghi trong ngọc giản, có đánh dấu vị trí các địa hỏa tử mạch. Do Đỗ Thanh mang tới cho Vương Lâm.","detail":"Ngọc giản chứa bản đồ toàn diện Thiên Ngưu Châu với các điểm địa hỏa tử mạch được đánh dấu rõ ràng. Vương Lâm dựa vào bản đồ này dùng bảy ngày phá hủy lần lượt các tử mạch khắp châu để ngưng tụ hỏa bổn nguyên chân thân.","congNang":["Chỉ dẫn vị trí các địa hỏa tử mạch trong Thiên Ngưu Châu"],"chuSoHuu":[{"ten":"Đỗ Thanh","tuChuong":"@c1724","denChuong":"@c1724","cachCoDuoc":"thu thập","trangThai":"đã chuyển giao"},{"ten":"Vương Lâm","tuChuong":"@c1724","denChuong":"","cachCoDuoc":"nhận từ Đỗ Thanh","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1724","loai":"xuất hiện","importance":"normal","giaiDoan":"Đỗ Thanh giao cho Vương Lâm","text":"Đỗ Thanh mang ngọc giản bản đồ Thiên Ngưu Châu có đánh dấu địa hỏa tử mạch tới giao cho Vương Lâm. Vương Lâm dựa vào đó dùng bảy ngày phá hủy các tử mạch khắp châu.","anchor":"mang theo một bản đồ đầy đủ của Thiên Ngưu Châu, bên trong bản đồ này có đánh dấu những nơi có địa hỏa tử mạch"}]},"nguon":["@c1724"]}]};
